export const LEGACY_ARCHIVE = {
  "commit": "053b01d",
  "routeTextByPath": {
    "/": "effect-first.coey.dev — plain-text Effect-TS reference for AI coding agents.\n\nEndpoints (all text/plain unless noted):\n\n  /rules       ~1000 tok  The 9 rules of Effect-first TypeScript. Terse, no examples.\n                           Token counts are now served in X-Token-Count headers.\n                           Use: you need the rules but already know the API surface.\n\n  /reference   ~800 tok   Imports, primitives, type signatures, quick-lookup tables.\n                           Use: you need a specific import path, type shape, or API name.\n\n  /examples    ~2300 tok  Copy-paste ready code patterns (gen, Layer, Schema, etc.).\n                           Use: you need concrete syntax to emit correct code.\n\n  /anti-patterns ~650 tok \"Never X -> do Y\" correction table.\n                           Use: you want to validate code or fix a known mistake.\n\n  /http-server ~1700 tok  HttpApi declarative server: endpoints, groups, handlers, security.\n                           Use: building an HTTP API with schema-validated routes.\n\n  /http-client ~1100 tok  HttpClient service: GET/POST, schema decoding, HttpApiClient.\n                           Use: making HTTP requests with typed errors and retry.\n\n  /sql         ~1650 tok  @effect/sql: tagged template queries, SqlSchema, Model, SqlResolver.\n                           Use: database access with validated queries and batching.\n\n  /cli         ~1250 tok  Command execution + CLI argument parsing.\n                           Use: running external processes or parsing env/argv config.\n\n  /streams     ~1400 tok  Stream, Sink, Channel: creation, transforms, consumption.\n                           Use: processing sequences of values with backpressure.\n\n  /concurrency ~450 tok   Structured concurrency: Effect.all, forEach, fibers, race.\n                           Use: parallel work, fork/join patterns, cancellations.\n\n  /resources   ~450 tok   Resource lifecycle: Scope, acquireRelease, Layer.scoped, Pool.\n                           Use: cleanup guarantees for connections, files, handles.\n\n  /full        ~7000 tok  Core sections combined (rules + reference + examples + anti-patterns\n                           + http + sql + cli + streams + concurrency + resources).\n                           Use: you have token budget and want the core in one fetch.\n\n  /bundle?modules=rules,reference  Combine modules in one response (comma-separated names).\n                           Use: build a custom bundle in one fetch.\n\n  /health      JSON       { \"ok\": true } — uptime check.\n\nTip: fetch /rules + /reference (~1800 tok) for most tasks. Add /examples only when generating new code.\nFor domain-specific work, add the relevant module endpoint (/http-server, /sql, etc.).\n",
    "/rules": "# Effect-First TypeScript — Rules\n\n## RULE 1 — Effect.fn for all named effectful functions\n- Wrap every named effectful function (including nullary) with Effect.fn(\"name\")(function* (...) { ... })\n- Optional second arg transforms the whole effect (retry, timeout, etc.)\n- Never use async functions for effectful code\n\n## RULE 2 — Effect.gen for sequencing\n- Use Effect.gen(function* () { ... }) to sequence effects\n- yield* each Effect; return final value\n\n## RULE 3 — Schema.TaggedError for all errors\n- Every error: class MyError extends Schema.TaggedError<MyError>()(\"MyError\", { ...fields })\n- Recover with Effect.catchTag(\"Tag\", handler) or Effect.catchAll\n- E channel = domain failures callers handle (not found, validation, rate limit)\n- Defects (Effect.die / Effect.orDie) = bugs/invariant violations, handled at boundary only\n\n## RULE 4 — Context.Tag + Layer for all services\n- class Svc extends Context.Tag(\"@scope/Svc\")<Svc, { readonly method: (...) => Effect.Effect<A, E> }>() {}\n- Tag IDs globally unique (@scope/Name)\n- Service methods must have R = never; dependencies resolved via Layer, not method signatures\n- Implement via static layer = Layer.effect(Tag, Effect.gen(function* () { ... }))\n- Layer names: layer, testLayer, postgresLayer (camelCase + Layer suffix)\n- Compose layers at entry point with Layer.provideMerge; provide once via Effect.provide(appLayer)\n- Parameterized layer constructors: assign to module-level const before reuse (memoization by reference)\n\n## RULE 5 — Schema for all data\n- Schema.Class for records: class User extends Schema.Class<User>(\"User\")({ ...fields }) {}\n- Schema.TaggedClass for union variants, discriminate with Match.valueTags\n- Brand all domain primitives: Schema.String.pipe(Schema.brand(\"UserId\"))\n- Type extraction: type UserId = typeof UserId.Type\n- JSON: Schema.parseJson(MySchema) for encode/decode\n\n## RULE 6 — Schema.Config + config service layers\n- Schema.Config(\"ENV_VAR\", MySchema) for validated/branded config\n- Config.redacted(\"SECRET\") for secrets (auto-hidden in logs)\n- Group related config into a single Context.Tag service with layer + testLayer\n\n## RULE 7 — Resilience via pipe\n- Chain: Effect.timeout, Effect.retry(Schedule.exponential(...).pipe(Schedule.compose(Schedule.recurs(n)))), Effect.tap, Effect.withSpan\n- Apply as .pipe() instrumentation on effects\n\n## RULE 8 — @effect/vitest for testing\n- it.effect(\"name\", () => Effect.gen(function* () { ... }).pipe(Effect.provide(Svc.testLayer)))\n- it.layer(Svc.testLayer)(\"suite\", (it) => { it.effect(...) }) for shared expensive resources\n- Test layers: Layer.sync(Tag, () => Tag.of({ ...in-memory impl }))\n\n## RULE 9 — Service-driven development workflow\n1. Sketch leaf service Tags (contracts, no impl)\n2. Write orchestration (higher-level services yield* leaf tags — compiles immediately)\n3. Implement leaf Layers\n4. Wire at entry point (compose into appLayer, provide once)\n\n## TypeScript Config (non-negotiable)\n- target: ES2022, module: NodeNext, moduleDetection: force\n- verbatimModuleSyntax: true, rewriteRelativeImportExtensions: true\n- strict: true, exactOptionalPropertyTypes: true\n- noUnusedLocals: true, noImplicitOverride: true\n- declarationMap: true, sourceMap: true, skipLibCheck: true\n",
    "/reference": "# Effect-TS Quick Reference\n\n## Imports\nimport { Effect, Layer, Context, Schema, Config, Schedule, Match, Redacted } from \"effect\"\nimport { HttpClient, HttpClientResponse } from \"@effect/platform\"\nimport { it, expect } from \"@effect/vitest\"\n\n## Type Signatures\nEffect<A, E, R>  A=success  E=typed-error  R=required-services\nSchema.Class<T>(\"Tag\")({ field: Schema.String })  — branded record\nSchema.TaggedError<T>()(\"Tag\", { field: Schema.X })  — typed error\nSchema.TaggedClass<T>()(\"Tag\", { field: Schema.X })  — tagged variant\nContext.Tag(\"@scope/Name\")<Tag, Interface>()  — service tag\nLayer.effect(Tag, Effect.gen(...))  — service impl\nLayer.sync(Tag, () => Tag.of({...}))  — sync/test impl\nLayer.succeed(Tag, Tag.of({...}))  — constant impl\n\n## Effect Primitives\nEffect.succeed(value)             pure value\nEffect.fail(error)                typed error (E channel)\nEffect.sync(() => expr)           wrap sync side-effect\nEffect.promise(() => fetch(...))  wrap Promise\nEffect.die(defect)                unrecoverable defect\nEffect.orDie                      promote E to defect\nEffect.logInfo(msg)               structured log\nEffect.logError(msg, cause)       error log\nEffect.runPromise(effect)         run at entry (async)\nEffect.runSync(effect)            run at entry (sync)\n\n## Generators\nEffect.gen(function* () { const x = yield* someEffect; return x })\nEffect.fn(\"name\")(function* (arg: T) { ... })  — named + traced\nEffect.fn(\"name\")(function* (...) { ... }, flow(Effect.retry(...), Effect.timeout(...)))  — with transform\n\n## .pipe() Combinators\nEffect.timeout(\"2 seconds\")\nEffect.retry(Schedule.exponential(\"100 millis\").pipe(Schedule.compose(Schedule.recurs(3))))\nEffect.tap((a) => Effect.logInfo(...))\nEffect.withSpan(\"spanName\")\nEffect.annotateCurrentSpan(\"key\", value)\nEffect.catchTag(\"ErrorTag\", (e) => fallback)\nEffect.catchAll((e) => fallback)\nEffect.provide(layer)\nEffect.orDie\n\n## Schema\nconst UserId = Schema.String.pipe(Schema.brand(\"UserId\"))\ntype UserId = typeof UserId.Type\nSchema.Config(\"ENV_VAR\", MySchema)  — validated config\nConfig.redacted(\"SECRET\")  — secrets (logs as <redacted>)\nSchema.parseJson(MySchema)  — JSON codec\nSchema.decodeUnknown(schema)(input)  — decode\nSchema.encode(schema)(value)  — encode\n\n## tsconfig compilerOptions (required)\ntarget: ES2022, module: NodeNext, moduleDetection: force,\nverbatimModuleSyntax: true, rewriteRelativeImportExtensions: true,\nstrict: true, exactOptionalPropertyTypes: true,\nnoUnusedLocals: true, noImplicitOverride: true,\ndeclarationMap: true, sourceMap: true, skipLibCheck: true\n",
    "/examples": "# Effect-First TypeScript — Code Examples\n\n## Effect.fn — basic\n\n    import { Effect } from \"effect\"\n\n    const processUser = Effect.fn(\"processUser\")(function* (userId: string) {\n      const user = yield* getUser(userId)\n      return yield* processData(user)\n    })\n\n## Effect.fn — with retry transform\n\n    import { Effect, Schedule, flow } from \"effect\"\n\n    const fetchWithRetry = Effect.fn(\"fetchWithRetry\")(\n      function* (url: string) {\n        return yield* fetchData(url)\n      },\n      flow(\n        Effect.retry(Schedule.exponential(\"100 millis\").pipe(Schedule.compose(Schedule.recurs(3)))),\n        Effect.timeout(\"5 seconds\")\n      )\n    )\n\n## Effect.gen — sequencing\n\n    import { Effect } from \"effect\"\n\n    const program = Effect.gen(function* () {\n      const data = yield* fetchData\n      yield* Effect.logInfo(`Processing: ${data}`)\n      return yield* processData(data)\n    })\n\n## TaggedError — definition\n\n    import { Schema } from \"effect\"\n\n    class UserNotFoundError extends Schema.TaggedError<UserNotFoundError>()(\n      \"UserNotFoundError\",\n      { id: Schema.String }\n    ) {}\n\n    class RateLimitError extends Schema.TaggedError<RateLimitError>()(\n      \"RateLimitError\",\n      { retryAfter: Schema.Number }\n    ) {}\n\n## TaggedError — recovery\n\n    const result = program.pipe(\n      Effect.catchTag(\"UserNotFoundError\", (e) => Effect.succeed(defaultUser)),\n      Effect.catchTag(\"RateLimitError\", (e) => Effect.fail(new FatalError({ cause: e })))\n    )\n\n    const safe = program.pipe(\n      Effect.catchAll((error) => Effect.gen(function* () {\n        yield* Effect.logError(\"Error\", error)\n        return fallback\n      }))\n    )\n\n## Service — Context.Tag definition\n\n    import { Context, Effect } from \"effect\"\n\n    class Database extends Context.Tag(\"@app/Database\")<\n      Database,\n      {\n        readonly query: (sql: string) => Effect.Effect<unknown[]>\n        readonly execute: (sql: string) => Effect.Effect<void>\n      }\n    >() {}\n\n## Service — Layer implementation with dependencies\n\n    import { Context, Effect, Layer } from \"effect\"\n\n    class Users extends Context.Tag(\"@app/Users\")<\n      Users,\n      {\n        readonly findById: (id: UserId) => Effect.Effect<User, UserNotFoundError>\n      }\n    >() {\n      static readonly layer = Layer.effect(\n        Users,\n        Effect.gen(function* () {\n          const db = yield* Database\n          const analytics = yield* Analytics\n\n          const findById = Effect.fn(\"Users.findById\")(function* (id: UserId) {\n            yield* analytics.track(\"user.find\", { id })\n            const rows = yield* db.query(`SELECT * FROM users WHERE id = '${id}'`)\n            if (rows.length === 0) return yield* new UserNotFoundError({ id })\n            return User.make(rows[0] as any)\n          })\n\n          return Users.of({ findById })\n        })\n      )\n    }\n\n## Schema — Class with branded ID\n\n    import { Schema } from \"effect\"\n\n    const UserId = Schema.String.pipe(Schema.brand(\"UserId\"))\n    type UserId = typeof UserId.Type\n\n    class User extends Schema.Class<User>(\"User\")({\n      id: UserId,\n      name: Schema.String,\n      email: Schema.String,\n      createdAt: Schema.Date,\n    }) {\n      get displayName() { return `${this.name} (${this.email})` }\n    }\n\n## Schema — branded primitives\n\n    const Email = Schema.String.pipe(Schema.brand(\"Email\"))\n    type Email = typeof Email.Type\n\n    const Port = Schema.Int.pipe(Schema.between(1, 65535), Schema.brand(\"Port\"))\n    type Port = typeof Port.Type\n\n## Schema — tagged union + Match\n\n    import { Match, Schema } from \"effect\"\n\n    class Success extends Schema.TaggedClass<Success>()(\"Success\", { value: Schema.Number }) {}\n    class Failure extends Schema.TaggedClass<Failure>()(\"Failure\", { error: Schema.String }) {}\n\n    const Result = Schema.Union(Success, Failure)\n    type Result = typeof Result.Type\n\n    const render = (r: Result) =>\n      Match.valueTags(r, {\n        Success: ({ value }) => `Got: ${value}`,\n        Failure: ({ error }) => `Error: ${error}`,\n      })\n\n## Schema — JSON encode/decode\n\n    const MoveFromJson = Schema.parseJson(Move)\n\n    // decode from JSON string\n    const move = yield* Schema.decodeUnknown(MoveFromJson)(jsonString)\n\n    // encode to JSON string\n    const json = yield* Schema.encode(MoveFromJson)(move)\n\n## Config — service layer with redacted secrets\n\n    import { Config, Context, Effect, Layer, Redacted, Schema } from \"effect\"\n\n    const Port = Schema.NumberFromString.pipe(Schema.int(), Schema.between(1, 65535), Schema.brand(\"Port\"))\n    type Port = typeof Port.Type\n\n    class AppConfig extends Context.Tag(\"@app/AppConfig\")<\n      AppConfig,\n      {\n        readonly port: Port\n        readonly apiKey: Redacted.Redacted\n        readonly env: \"development\" | \"staging\" | \"production\"\n      }\n    >() {\n      static readonly layer = Layer.effect(\n        AppConfig,\n        Effect.gen(function* () {\n          const port   = yield* Schema.Config(\"PORT\", Port)\n          const apiKey = yield* Config.redacted(\"API_KEY\")\n          const env    = yield* Schema.Config(\"ENV\", Schema.Literal(\"development\", \"staging\", \"production\"))\n          return AppConfig.of({ port, apiKey, env })\n        })\n      )\n\n      static readonly testLayer = Layer.succeed(AppConfig, AppConfig.of({\n        port: Port.make(3000),\n        apiKey: Redacted.make(\"test-key\"),\n        env: \"development\",\n      }))\n    }\n\n## Resilience — retry, timeout, span\n\n    import { Effect, Schedule } from \"effect\"\n\n    const retryPolicy = Schedule.exponential(\"100 millis\").pipe(\n      Schedule.compose(Schedule.recurs(3))\n    )\n\n    const resilient = callExternalApi.pipe(\n      Effect.timeout(\"2 seconds\"),\n      Effect.retry(retryPolicy),\n      Effect.timeout(\"10 seconds\"),\n      Effect.tap((data) => Effect.logInfo(`Fetched: ${data}`)),\n      Effect.withSpan(\"callExternalApi\")\n    )\n\n## Testing — per-test layer (preferred)\n\n    import { expect, it } from \"@effect/vitest\"\n    import { Effect } from \"effect\"\n\n    it.effect(\"creates a user\", () =>\n      Effect.gen(function* () {\n        const users = yield* Users\n        const user = yield* users.findById(UserId.make(\"u-1\"))\n        expect(user.name).toBe(\"Alice\")\n      }).pipe(Effect.provide(Users.testLayer))\n    )\n\n## Testing — suite-shared layer\n\n    it.layer(Users.testLayer)(\"users suite\", (it) => {\n      it.effect(\"finds user\", () => Effect.gen(function* () {\n        const users = yield* Users\n        expect(yield* users.findById(UserId.make(\"u-1\"))).toBeDefined()\n      }))\n    })\n\n## Testing — in-memory test layer\n\n    static readonly testLayer = Layer.sync(Users, () => {\n      const store = new Map([[\"u-1\", User.make({ id: UserId.make(\"u-1\"), name: \"Alice\", email: \"a@example.com\", createdAt: new Date() })]])\n      return Users.of({\n        findById: (id) => Effect.succeed(store.get(id)!),\n      })\n    })\n\n## Layer composition — entry point\n\n    import { Layer, Effect } from \"effect\"\n\n    const dbLayer = Postgres.layer({ url: \"postgres://localhost/mydb\", poolSize: 10 })\n\n    const appLayer = UsersLayer.pipe(\n      Layer.provideMerge(dbLayer),\n      Layer.provideMerge(AnalyticsLayer),\n      Layer.provideMerge(ConfigLayer)\n    )\n\n    Effect.runPromise(program.pipe(Effect.provide(appLayer)))\n\n## Defect promotion — orDie at entry point\n\n    const main = Effect.gen(function* () {\n      const config = yield* loadConfig.pipe(Effect.orDie)\n      yield* startServer(config)\n    })\n",
    "/anti-patterns": "WRONG: async function foo() { ... }\nRIGHT: const foo = Effect.fn(\"foo\")(function* () { ... })\n\nWRONG: try { ... } catch (e) { ... }\nRIGHT: Effect.catchTag / Effect.catchAll\n\nWRONG: throw new Error(\"not found\")\nRIGHT: yield* new UserNotFoundError({ id }) (Schema.TaggedError)\n\nWRONG: class MyError extends Error { ... }\nRIGHT: class MyError extends Schema.TaggedError<MyError>()(\"MyError\", { ... }) {}\n\nWRONG: Promise<T> as service method return type\nRIGHT: Effect.Effect<A, E> as service method return type\n\nWRONG: Calling Postgres.layer(...) in multiple places\nRIGHT: const dbLayer = Postgres.layer(...) — assign once, share reference\n\nWRONG: Scattered Effect.provide(...) throughout codebase\nRIGHT: Provide once at entry point via composed appLayer\n\nWRONG: Effect.provide inside service method implementations\nRIGHT: Layer composition handles all dependency wiring\n\nWRONG: Config.string(\"PORT\") for validated/branded values\nRIGHT: Schema.Config(\"PORT\", Port)\n\nWRONG: console.log(apiKey) or Config.string(\"SECRET\")\nRIGHT: Config.redacted(\"SECRET\") — logs as <redacted>\n\nWRONG: Raw string for domain IDs (userId: string)\nRIGHT: Schema.String.pipe(Schema.brand(\"UserId\"))\n\nWRONG: Plain generator function* for effectful code\nRIGHT: Effect.fn(\"name\")(function* (...) { ... }) for tracing + spans\n\nWRONG: Effect.gen without yield* (using .then or await)\nRIGHT: yield* inside Effect.gen(function* () { ... })\n\nWRONG: interface + manual tag for services\nRIGHT: class Db extends Context.Tag(\"@app/Db\")<Db, { ... }>() {}\n\nWRONG: Inline object literals for data models\nRIGHT: Schema.Class / Schema.TaggedClass for runtime-validated models\n\nWRONG: Union types via string literals or manual discriminants\nRIGHT: Schema.Union(VariantA, VariantB) + Match.valueTags\n\nWRONG: Mutable service interface properties\nRIGHT: readonly on all service interface properties\n\nWRONG: it(\"test\", async () => { ... }) with manual runPromise\nRIGHT: it.effect(\"test\", () => Effect.gen(function* () { ... }))\n\nWRONG: Writing full implementation before defining service contracts\nRIGHT: Sketch Context.Tag contracts first, implement layers after\n",
    "/http-server": "# Effect-First TypeScript — HTTP Server (HttpApi)\n\nPackage: @effect/platform (HttpApi, HttpApiBuilder, HttpApiEndpoint, HttpApiGroup, HttpApiMiddleware, HttpApiSecurity)\n\n## Imports\n\n    import {\n      HttpApi, HttpApiBuilder, HttpApiEndpoint, HttpApiGroup,\n      HttpApiMiddleware, HttpApiSecurity\n    } from \"@effect/platform\"\n\n## Step 1 — Define endpoints\n\n    import { HttpApiEndpoint, HttpApiGroup, HttpApi } from \"@effect/platform\"\n    import { Schema } from \"effect\"\n\n    class User extends Schema.Class<User>(\"User\")({\n      id: Schema.String,\n      name: Schema.String,\n    }) {}\n\n    class UserNotFound extends Schema.TaggedError<UserNotFound>()(\"UserNotFound\", {\n      id: Schema.String,\n    }) {}\n\n    class UsersGroup extends HttpApiGroup.make(\"users\")\n      .add(\n        HttpApiEndpoint.get(\"findById\", \"/users/:id\")\n          .setPath(Schema.Struct({ id: Schema.String }))\n          .addSuccess(User)\n          .addError(UserNotFound, { status: 404 })\n      )\n      .add(\n        HttpApiEndpoint.post(\"create\", \"/users\")\n          .setPayload(Schema.Struct({ name: Schema.NonEmptyString }))\n          .addSuccess(User, { status: 201 })\n      )\n      .prefix(\"/api\") {}\n\n    class MyApi extends HttpApi.make(\"myApi\").add(UsersGroup) {}\n\n\n## Step 2 — Implement handlers\n\n    import { HttpApiBuilder } from \"@effect/platform\"\n    import { Effect, Layer } from \"effect\"\n\n    const UsersGroupLive = HttpApiBuilder.group(MyApi, \"users\", (handlers) =>\n      handlers\n        .handle(\"findById\", ({ path }) =>\n          Effect.gen(function* () {\n            const users = yield* Users\n            return yield* users.findById(path.id)\n          })\n        )\n        .handle(\"create\", ({ payload }) =>\n          Effect.gen(function* () {\n            const users = yield* Users\n            return yield* users.create(payload.name)\n          })\n        )\n    )\n\n\n## Step 3 — Serve\n\n    import { NodeHttpServer } from \"@effect/platform-node\"\n    import { HttpApiBuilder } from \"@effect/platform\"\n    import { Layer, Effect } from \"effect\"\n    import { createServer } from \"node:http\"\n\n    const ApiLive = HttpApiBuilder.api(MyApi).pipe(\n      Layer.provide(UsersGroupLive),\n      Layer.provide(Users.layer)\n    )\n\n    const ServerLive = NodeHttpServer.layer(createServer, { port: 3000 })\n\n    const app = HttpApiBuilder.serve().pipe(\n      Layer.provide(ServerLive),\n      Layer.provide(ApiLive)\n    )\n\n    Layer.launch(app).pipe(Effect.runPromise)\n\n\n## HttpApi key constructors\n\n    HttpApi.make(id)                                — create API\n    HttpApiGroup.make(id)                           — create group\n    HttpApiEndpoint.get(name, path)                 — GET endpoint\n    HttpApiEndpoint.post(name, path)                — POST endpoint\n    HttpApiEndpoint.put(name, path)                 — PUT endpoint\n    HttpApiEndpoint.del(name, path)                 — DELETE endpoint\n    HttpApiEndpoint.patch(name, path)               — PATCH endpoint\n\n## Endpoint schema methods (chainable)\n\n    .setPath(Schema.Struct({ id: Schema.String }))  — path params\n    .setPayload(schema)                              — request body (POST/PUT/PATCH)\n    .setUrlParams(schema)                            — query string params (GET)\n    .setHeaders(schema)                              — required headers\n    .addSuccess(schema, { status: 200 })             — success response\n    .addError(schema, { status: 404 })               — error response\n    .prefix(\"/v1\")                                   — path prefix\n\n## Group / API composition\n\n    group.add(endpoint)                              — add endpoint to group\n    group.addError(schema, { status })               — shared error for all endpoints\n    group.prefix(\"/api\")                             — prefix all routes\n    api.add(group)                                   — add group to api\n    api.addError(schema, { status })                 — global error\n\n## Builder\n\n    HttpApiBuilder.api(MyApi)                        — Layer<HttpApi.Api>\n    HttpApiBuilder.group(api, name, build)           — Layer for a group\n    HttpApiBuilder.serve()                           — Layer that starts server\n    HttpApiBuilder.toWebHandler(layer)               — { handler, dispose } for Cloudflare/Bun\n\n\n## Security\n\n    import { HttpApiSecurity, HttpApiMiddleware } from \"@effect/platform\"\n\n    class AuthMiddleware extends HttpApiMiddleware.Tag<AuthMiddleware>()(\"AuthMiddleware\", {\n      provides: CurrentUser,\n      security: { bearer: HttpApiSecurity.bearer },\n    }) {}\n\n    // Apply to group\n    class SecureGroup extends HttpApiGroup.make(\"secure\")\n      .middleware(AuthMiddleware)\n      .add(...) {}\n\n    // Implement middleware\n    const AuthMiddlewareLive = Layer.effect(AuthMiddleware, Effect.gen(function* () {\n      return AuthMiddleware.of({\n        bearer: (token) => Effect.gen(function* () {\n          // validate token, return CurrentUser\n        })\n      })\n    }))\n\n\n## Anti-patterns\n\nWRONG: Manual HttpRouter.get/post for typed APIs\nRIGHT: HttpApi + HttpApiEndpoint for schema-validated, auto-documented endpoints\n\nWRONG: Parsing request body manually in handlers\nRIGHT: .setPayload(schema) — decoded and validated before handler runs\n\nWRONG: Returning HttpServerResponse from handlers\nRIGHT: Return domain types; framework encodes via success/error schemas\n\nWRONG: Implementing auth checks inside each handler\nRIGHT: HttpApiMiddleware + HttpApiSecurity applied to group or api\n",
    "/http-client": "# Effect-First TypeScript — HTTP Client\n\nPackage: @effect/platform (HttpClient, HttpClientRequest, HttpClientResponse, HttpClientError)\n\n## Imports\n\n    import { HttpClient, HttpClientRequest, HttpClientResponse, FetchHttpClient } from \"@effect/platform\"\n    import { NodeHttpClient } from \"@effect/platform-node\"\n    import { Effect, Schema } from \"effect\"\n\n## Basic GET\n\n    const fetchUser = Effect.fn(\"fetchUser\")(function* (id: string) {\n      const client = yield* HttpClient.HttpClient\n      const response = yield* client.get(`https://api.example.com/users/${id}`)\n      return yield* HttpClientResponse.schemaBodyJson(User)(response)\n    })\n\n    // Provide the client layer\n    fetchUser(\"u-1\").pipe(Effect.provide(FetchHttpClient.layer))\n\n## POST with JSON body\n\n    const createUser = Effect.fn(\"createUser\")(function* (name: string) {\n      const client = yield* HttpClient.HttpClient\n      const request = HttpClientRequest.post(\"https://api.example.com/users\").pipe(\n        HttpClientRequest.jsonBody({ name })\n      )\n      const response = yield* client.execute(request)\n      return yield* HttpClientResponse.schemaBodyJson(User)(response)\n    })\n\n## HttpApiClient — typed client from HttpApi definition\n\n    import { HttpApiClient } from \"@effect/platform\"\n\n    const program = Effect.gen(function* () {\n      const client = yield* HttpApiClient.make(MyApi, {\n        baseUrl: \"https://api.example.com\",\n      })\n      const user = yield* client.users.findById({ path: { id: \"u-1\" } })\n    })\n\n## Resilience — retry + timeout\n\n    const resilientFetch = fetchUser(\"u-1\").pipe(\n      Effect.retry(Schedule.exponential(\"200 millis\").pipe(Schedule.compose(Schedule.recurs(3)))),\n      Effect.timeout(\"10 seconds\"),\n      Effect.withSpan(\"fetchUser\")\n    )\n\n\n## Key types\n\n    HttpClient.HttpClient                — Context.Tag for the client service\n    HttpClientRequest.HttpClientRequest  — immutable request description\n    HttpClientResponse.HttpClientResponse — response with schema decoding\n    HttpClientError.HttpClientError      — typed error (RequestError | ResponseError)\n\n## Client methods\n\n    client.get(url, options?)            — GET request\n    client.post(url, options?)           — POST request\n    client.put(url, options?)            — PUT request\n    client.del(url, options?)            — DELETE request\n    client.patch(url, options?)          — PATCH request\n    client.head(url, options?)           — HEAD request\n    client.execute(request)              — execute arbitrary request\n\n## Response decoding\n\n    HttpClientResponse.schemaBodyJson(schema)(response)   — decode JSON body\n    HttpClientResponse.text(response)                     — body as string\n    HttpClientResponse.json(response)                     — body as unknown JSON\n    HttpClientResponse.stream(response)                   — body as Stream<Uint8Array>\n\n## Layers\n\n    FetchHttpClient.layer                — uses globalThis.fetch (browser, Cloudflare Workers, Bun)\n    NodeHttpClient.layer                 — uses Node.js undici\n\n## Anti-patterns\n\nWRONG: fetch(url).then(r => r.json())\nRIGHT: client.get(url) |> HttpClientResponse.schemaBodyJson(Schema)\n\nWRONG: Manual error handling for HTTP status codes\nRIGHT: HttpClient errors are typed; use Effect.catchTag(\"ResponseError\", ...)\n\nWRONG: Hardcoding fetch in service implementations\nRIGHT: Depend on HttpClient.HttpClient tag; provide FetchHttpClient.layer or NodeHttpClient.layer\n\nWRONG: Building typed API clients by hand\nRIGHT: HttpApiClient.make(MyApi) generates fully typed client from HttpApi definition\n",
    "/sql": "# Effect-First TypeScript — SQL (@effect/sql)\n\n@effect/sql provides a tagged template literal SQL client, schema-validated queries, batched resolvers, and a Model system for domain objects with insert/update/json variants.\n\nPackage: @effect/sql (SqlClient, SqlSchema, SqlResolver, Model, Migrator)\nDB adapters: @effect/sql-pg, @effect/sql-sqlite-node, @effect/sql-mysql2, @effect/sql-mssql\n\n\n## Imports\n\n    import { SqlClient, SqlSchema, SqlResolver, Model } from \"@effect/sql\"\n    import { PgClient } from \"@effect/sql-pg\"        // or SqliteClient, etc.\n    import { Effect, Schema } from \"effect\"\n\n\n## SqlClient — tagged template queries\n\n    const program = Effect.gen(function* () {\n      const sql = yield* SqlClient.SqlClient\n\n      // select — returns ReadonlyArray<unknown>\n      const rows = yield* sql`SELECT * FROM users WHERE id = ${userId}`\n\n      // insert\n      yield* sql`INSERT INTO users ${sql.insert({ id, name, email })}`\n\n      // update\n      yield* sql`UPDATE users SET ${sql.update({ name, email })} WHERE id = ${id}`\n\n      // transactions\n      yield* sql.withTransaction(\n        Effect.gen(function* () {\n          yield* sql`INSERT INTO orders ${sql.insert(order)}`\n          yield* sql`UPDATE inventory SET qty = qty - 1 WHERE id = ${itemId}`\n        })\n      )\n    })\n\n\n## SqlSchema — validated queries\n\n    import { SqlClient, SqlSchema } from \"@effect/sql\"\n    import { Effect, Schema } from \"effect\"\n\n    const findUserById = SqlSchema.findOne({\n      Request: Schema.String,\n      Result: User,\n      execute: (id) => Effect.gen(function* () {\n        const sql = yield* SqlClient.SqlClient\n        return yield* sql`SELECT * FROM users WHERE id = ${id}`\n      }),\n    })\n\n    // SqlSchema variants:\n    // SqlSchema.findAll    — returns ReadonlyArray<A>\n    // SqlSchema.findOne    — returns Option<A>\n    // SqlSchema.single     — returns A (throws NoSuchElementException if missing)\n    // SqlSchema.void       — discards result\n\n\n## Model — domain objects with variants\n\n    import { Model } from \"@effect/sql\"\n    import { Schema } from \"effect\"\n\n    const GroupId = Schema.Number.pipe(Schema.brand(\"GroupId\"))\n\n    class Group extends Model.Class<Group>(\"Group\")({\n      id: Model.Generated(GroupId),\n      name: Schema.NonEmptyTrimmedString,\n      createdAt: Model.DateTimeInsertFromDate,\n      updatedAt: Model.DateTimeUpdateFromDate,\n    }) {}\n\n    // Variants auto-generated:\n    // Group            — select schema (all fields)\n    // Group.insert     — insert schema (id omitted, createdAt auto)\n    // Group.update     — update schema (all optional, updatedAt auto)\n    // Group.json       — JSON API schema\n    // Group.jsonCreate — JSON create schema\n    // Group.jsonUpdate — JSON update schema\n\n    // Model field helpers:\n    // Model.Generated(schema)              — omit from insert\n    // Model.GeneratedByApp(schema)         — required in insert, not from DB\n    // Model.DateTimeInsertFromDate         — auto DateTime on insert\n    // Model.DateTimeUpdateFromDate         — auto DateTime on update\n    // Model.Sensitive(schema)              — omit from json variants\n    // Model.FieldOption(schema)            — Option<A> field\n    // Model.JsonFromString(schema)         — JSON stored as string column\n\n\n## SqlResolver — batched queries with Effect Request\n\n    const UserById = SqlResolver.findById(\"UserById\", {\n      Id: UserId,\n      Result: User,\n      ResultId: (user) => user.id,\n      execute: (ids) => Effect.gen(function* () {\n        const sql = yield* SqlClient.SqlClient\n        return yield* sql`SELECT * FROM users WHERE id IN ${sql.in(ids)}`\n      }),\n    })\n\n    // Use:\n    const user = yield* UserById.execute(userId)\n\n    // SqlResolver variants:\n    // SqlResolver.findById   — returns Option<A>, keyed by ID\n    // SqlResolver.ordered    — results match request order 1:1\n    // SqlResolver.grouped    — group results by key (1:many)\n    // SqlResolver.void       — batched writes, no result\n\n\n## Model.makeRepository — CRUD from Model\n\n    const GroupRepo = Model.makeRepository(Group, {\n      tableName: \"groups\",\n      spanPrefix: \"GroupRepo\",\n      idColumn: \"id\",\n    })\n\n    // Provides: findById, insert, update, delete, etc.\n\n\n## Layers (provide at entry point)\n\n    // PostgreSQL\n    import { PgClient } from \"@effect/sql-pg\"\n    const DbLive = PgClient.layer({ url: \"postgres://localhost/mydb\" })\n\n    // SQLite\n    import { SqliteClient } from \"@effect/sql-sqlite-node\"\n    const DbLive = SqliteClient.layer({ filename: \"./data.db\" })\n\n    // Always assign to a const — memoization by reference\n    Effect.runPromise(program.pipe(Effect.provide(DbLive)))\n\n\n## Anti-patterns\n\nWRONG: String concatenation for SQL queries\nRIGHT: Tagged template: sql`SELECT * FROM users WHERE id = ${id}` (auto-parameterized)\n\nWRONG: Manual row-to-object mapping\nRIGHT: SqlSchema.findAll/findOne with Schema for validated decoding\n\nWRONG: N+1 queries in loops\nRIGHT: SqlResolver.findById / SqlResolver.grouped for automatic batching\n\nWRONG: Separate type definitions for insert vs select\nRIGHT: Model.Class generates all variants (select, insert, update, json) from one definition\n\nWRONG: Manual transaction begin/commit/rollback\nRIGHT: sql.withTransaction(effect) handles commit/rollback automatically\n",
    "/cli": "# Effect-First TypeScript — CLI & Commands\n\nEffect provides two distinct capabilities:\n1. Command execution — run external processes via @effect/platform Command\n2. CLI argument parsing — use effect Config + Schema.Config for argv/env, or @effect/cli for full CLI apps\n\n\n## Imports\n\n    import { Command, CommandExecutor } from \"@effect/platform\"\n    import { NodeCommandExecutor, NodeFileSystem } from \"@effect/platform-node\"\n    import { Effect, Stream } from \"effect\"\n\n\n## Running external commands\n\n    const listFiles = Effect.gen(function* () {\n      // Simple: get stdout as string\n      const output = yield* Command.make(\"ls\", \"-la\").pipe(Command.string)\n\n      // With options\n      const result = yield* Command.make(\"git\", \"status\")\n        .pipe(\n          Command.workingDirectory(\"/path/to/repo\"),\n          Command.env({ GIT_AUTHOR_NAME: \"bot\" }),\n          Command.string\n        )\n\n      // Exit code only\n      const code = yield* Command.make(\"npm\", \"test\").pipe(Command.exitCode)\n\n      return output\n    })\n\n    // Provide the executor\n    listFiles.pipe(\n      Effect.provide(NodeCommandExecutor.layer),\n      Effect.provide(NodeFileSystem.layer)\n    )\n\n\n## Streaming output\n\n    // Stream stdout line by line\n    const logStream = Command.make(\"tail\", \"-f\", \"/var/log/app.log\").pipe(\n      Command.streamLines\n    )\n\n    // Process as a stream\n    const program = logStream.pipe(\n      Stream.filter((line) => line.includes(\"ERROR\")),\n      Stream.tap((line) => Effect.logError(line)),\n      Stream.runDrain\n    )\n\n    // Raw byte stream\n    const bytes = Command.make(\"cat\", \"file.bin\").pipe(Command.stream)\n\n\n## Piping commands\n\n    const pipeline = Command.make(\"cat\", \"data.csv\").pipe(\n      Command.pipeTo(Command.make(\"grep\", \"error\")),\n      Command.pipeTo(Command.make(\"wc\", \"-l\")),\n      Command.string\n    )\n\n\n## Process with stdin\n\n    const withInput = Command.make(\"wc\", \"-w\").pipe(\n      Command.feed(\"hello world this is a test\"),\n      Command.string\n    )\n\n\n## Command API reference\n\n    Command.make(cmd, ...args)           — create command\n    Command.string(cmd)                  — run, return stdout as string\n    Command.lines(cmd)                   — run, return stdout as string[]\n    Command.exitCode(cmd)                — run, return exit code\n    Command.stream(cmd)                  — stdout as Stream<Uint8Array>\n    Command.streamLines(cmd)             — stdout as Stream<string>\n    Command.start(cmd)                   — start Process (stdin/stdout/stderr access)\n    Command.pipeTo(target)               — pipe stdout to another command\n    Command.feed(input)                  — feed string to stdin\n    Command.workingDirectory(path)       — set cwd\n    Command.env(record)                  — set env vars\n    Command.runInShell(shell)            — run via shell (boolean | string)\n\n## Layers\n\n    NodeCommandExecutor.layer            — Node.js process execution\n    NodeFileSystem.layer                 — required by NodeCommandExecutor\n\n\n## CLI argument parsing with Config\n\nFor simple CLIs, use effect’s Config module (reads from env + argv):\n\n    import { Config, Effect, Schema } from \"effect\"\n\n    const program = Effect.gen(function* () {\n      const port = yield* Schema.Config(\"PORT\", Schema.NumberFromString.pipe(\n        Schema.int(), Schema.between(1, 65535)\n      ))\n      const verbose = yield* Config.withDefault(Config.boolean(\"VERBOSE\"), false)\n      const dbUrl = yield* Config.redacted(\"DATABASE_URL\")\n      yield* Effect.logInfo(`Starting on port ${port}`)\n    })\n\n\n## Anti-patterns\n\nWRONG: child_process.exec(cmd, callback)\nRIGHT: Command.make(cmd).pipe(Command.string)\n\nWRONG: Manually parsing stdout string into lines\nRIGHT: Command.streamLines(cmd) returns Stream<string>\n\nWRONG: process.env.PORT with manual parseInt\nRIGHT: Schema.Config(\"PORT\", Schema.NumberFromString) with validation\n\nWRONG: Forgetting to provide CommandExecutor layer\nRIGHT: Effect.provide(NodeCommandExecutor.layer) + Effect.provide(NodeFileSystem.layer)\n",
    "/streams": "# Effect-First TypeScript — Streams\n\nStream<A, E, R> is a pull-based, backpressured sequence of values.\n\nPackage: effect (Stream, Sink, Channel)\n\n## Imports\n\n    import { Stream, Sink, Chunk, Effect, Schedule } from \"effect\"\n\n## Creating streams\n\n    // From values\n    Stream.make(1, 2, 3)\n    Stream.fromIterable([1, 2, 3])\n    Stream.range(1, 100)\n    Stream.empty\n\n    // From Effect (single value stream)\n    Stream.fromEffect(fetchUser(id))\n\n    // Repeated effect\n    Stream.repeatEffect(readSensor)\n    Stream.repeatEffectWithSchedule(pollApi, Schedule.spaced(\"5 seconds\"))\n\n    // Pagination\n    Stream.paginate(initialCursor, (cursor) => {\n      const page = fetchPage(cursor)\n      return [page.items, Option.fromNullable(page.nextCursor)]\n    })\n\n    // From async\n    Stream.fromAsyncIterable(asyncIter, (e) => new MyError({ cause: e }))\n    Stream.async((emit) => { /* push values via emit */ })\n\n    // Infinite\n    Stream.iterate(0, (n) => n + 1)\n    Stream.repeatValue(\"tick\")\n\n\n## Transforming streams\n\n    stream.pipe(\n      Stream.map((x) => x * 2),\n      Stream.filter((x) => x > 10),\n      Stream.take(5),\n      Stream.drop(2),\n      Stream.flatMap((x) => Stream.make(x, x + 1)),\n      Stream.mapEffect((x) => processItem(x)),\n      Stream.tap((x) => Effect.logInfo(`Processing: ${x}`)),\n      Stream.scan(0, (acc, x) => acc + x),\n    )\n\n    // Chunked operations (batch-efficient)\n    stream.pipe(\n      Stream.mapChunks((chunk) => Chunk.map(chunk, transform)),\n      Stream.grouped(100),           // group into chunks of 100\n      Stream.debounce(\"500 millis\"), // debounce emissions\n    )\n\n\n## Consuming streams\n\n    // Collect all (careful with large streams)\n    const items = yield* Stream.runCollect(stream)  // Chunk<A>\n\n    // Fold\n    const sum = yield* Stream.runFold(stream, 0, (acc, x) => acc + x)\n\n    // ForEach (side effects)\n    yield* Stream.runForEach(stream, (item) => processItem(item))\n\n    // Drain (discard values, run for effects)\n    yield* Stream.runDrain(stream)\n\n    // Count\n    const n = yield* Stream.runCount(stream)\n\n    // With Sink\n    yield* Stream.run(stream, Sink.collectAll())\n    yield* Stream.run(stream, Sink.foldLeft(0, (acc, x) => acc + x))\n\n\n## Combining streams\n\n    // Merge (interleave, concurrent)\n    Stream.merge(streamA, streamB)\n    Stream.mergeAll([streamA, streamB, streamC], { concurrency: 3 })\n\n    // Concat (sequential)\n    Stream.concat(streamA, streamB)\n\n    // Zip (pair elements)\n    Stream.zip(streamA, streamB)          // Stream<[A, B]>\n    Stream.zipWith(streamA, streamB, (a, b) => a + b)\n\n\n## Error handling\n\n    stream.pipe(\n      Stream.catchAll((e) => Stream.make(fallbackValue)),\n      Stream.catchTag(\"NetworkError\", (e) => Stream.empty),\n      Stream.retry(Schedule.exponential(\"1 second\")),\n    )\n\n\n## Sinks (stream consumers)\n\n    Sink.collectAll()                    — collect into Chunk<A>\n    Sink.foldLeft(init, f)               — fold without early termination\n    Sink.fold(init, contFn, f)           — fold with early termination\n    Sink.forEach(f)                      — side-effect per element\n    Sink.head                            — first element as Option<A>\n    Sink.last                            — last element as Option<A>\n    Sink.count                           — count elements\n    Sink.sum                             — sum numbers\n    Sink.take(n)                         — take first n into Chunk<A>\n\n\n## Common patterns\n\n    // Polling with schedule\n    const poller = Stream.repeatEffectWithSchedule(\n      checkStatus,\n      Schedule.spaced(\"10 seconds\")\n    ).pipe(\n      Stream.takeUntil((status) => status === \"complete\")\n    )\n\n    // Batched processing\n    const batchProcessor = eventStream.pipe(\n      Stream.grouped(50),\n      Stream.mapEffect((batch) => processBatch(Chunk.toReadonlyArray(batch)),\n        { concurrency: 3 }\n      ),\n      Stream.runDrain\n    )\n\n\n## Anti-patterns\n\nWRONG: Collecting unbounded stream into array\nRIGHT: Stream.runForEach or Stream.runFold for bounded consumption\n\nWRONG: for await (const x of asyncIter) with manual error handling\nRIGHT: Stream.fromAsyncIterable + Stream.mapEffect for typed errors\n\nWRONG: setInterval + mutable array for polling\nRIGHT: Stream.repeatEffectWithSchedule + Stream.takeUntil\n\nWRONG: Manual batching with counters\nRIGHT: Stream.grouped(n) + Stream.mapEffect with concurrency\n\nWRONG: Promise.all for concurrent stream processing\nRIGHT: Stream.mergeAll with concurrency option\n",
    "/concurrency": "# Effect-First TypeScript — Concurrency\n\n## Imports\n\n    import { Effect, Fiber, FiberSet, FiberMap } from \"effect\"\n\n## Structured concurrency\n\n    // Run in parallel (all succeed or first error)\n    const result = yield* Effect.all([taskA, taskB, taskC], { concurrency: 2 })\n\n    // ForEach with concurrency + batching\n    yield* Effect.forEach(items, (item) => process(item), { concurrency: 5 })\n\n## Fork / join\n\n    const fiber = yield* Effect.fork(task)\n    const value = yield* Fiber.join(fiber)\n\n    // Fork and interrupt\n    const fiber = yield* Effect.fork(longRunning)\n    yield* Fiber.interrupt(fiber)\n\n    // Scoped fork (auto-interrupt on scope close)\n    const fiber = yield* Effect.forkScoped(task)\n    yield* Fiber.join(fiber)\n\n## Race\n\n    const fastest = yield* Effect.race(taskA, taskB)\n    const winner = yield* Effect.raceAll([taskA, taskB, taskC])\n\n## Fiber collections\n\n    const set = yield* FiberSet.make()\n    yield* FiberSet.run(set, taskA)\n    yield* FiberSet.run(set, taskB)\n    yield* FiberSet.join(set)\n\n    const map = yield* FiberMap.make()\n    yield* FiberMap.run(map, \"job-1\", taskA)\n    yield* FiberMap.run(map, \"job-2\", taskB)\n    yield* FiberMap.join(map, \"job-1\")\n\n## Interrupt\n\n    const fiber = yield* Effect.fork(task)\n    yield* Fiber.interrupt(fiber)\n    yield* Fiber.await(fiber)  // observe exit\n",
    "/resources": "# Effect-First TypeScript — Resources & Scope\n\n## Imports\n\n    import { Effect, Layer, Scope, Pool, ScopedRef } from \"effect\"\n\n## acquireRelease\n\n    const file = yield* Effect.acquireRelease(\n      openFile(path),\n      (handle) => closeFile(handle)\n    )\n\n    const program = Effect.acquireUseRelease(\n      connectDb,\n      (db) => db.query(\"select * from users\"),\n      (db) => db.close\n    )\n\n## addFinalizer\n\n    const program = Effect.gen(function* () {\n      yield* Effect.addFinalizer(() => Effect.logInfo(\"cleanup\"))\n      return yield* doWork\n    })\n\n## Scope service\n\n    const scoped = Effect.scoped(\n      Effect.gen(function* () {\n        const scope = yield* Scope.Scope\n        return scope\n      })\n    )\n\n## Layer.scoped\n\n    class Connection extends Context.Tag(\"@app/Connection\")<\n      Connection,\n      { readonly query: (sql: string) => Effect.Effect<unknown[]> }\n    >() {}\n\n    const ConnectionLive = Layer.scoped(\n      Connection,\n      Effect.acquireRelease(connectDb, (db) => db.close)\n    )\n\n## Pools\n\n    const pool = yield* Pool.make({\n      acquire: connectDb,\n      size: 10,\n      timeToLive: \"10 minutes\",\n      concurrency: 2,\n    })\n\n    const db = yield* Pool.get(pool)\n\n## ScopedRef\n\n    const ref = yield* ScopedRef.fromAcquire(connectDb)\n    const db = yield* ScopedRef.get(ref)\n",
    "/full": "# Effect-First TypeScript — Rules\n\n## RULE 1 — Effect.fn for all named effectful functions\n- Wrap every named effectful function (including nullary) with Effect.fn(\"name\")(function* (...) { ... })\n- Optional second arg transforms the whole effect (retry, timeout, etc.)\n- Never use async functions for effectful code\n\n## RULE 2 — Effect.gen for sequencing\n- Use Effect.gen(function* () { ... }) to sequence effects\n- yield* each Effect; return final value\n\n## RULE 3 — Schema.TaggedError for all errors\n- Every error: class MyError extends Schema.TaggedError<MyError>()(\"MyError\", { ...fields })\n- Recover with Effect.catchTag(\"Tag\", handler) or Effect.catchAll\n- E channel = domain failures callers handle (not found, validation, rate limit)\n- Defects (Effect.die / Effect.orDie) = bugs/invariant violations, handled at boundary only\n\n## RULE 4 — Context.Tag + Layer for all services\n- class Svc extends Context.Tag(\"@scope/Svc\")<Svc, { readonly method: (...) => Effect.Effect<A, E> }>() {}\n- Tag IDs globally unique (@scope/Name)\n- Service methods must have R = never; dependencies resolved via Layer, not method signatures\n- Implement via static layer = Layer.effect(Tag, Effect.gen(function* () { ... }))\n- Layer names: layer, testLayer, postgresLayer (camelCase + Layer suffix)\n- Compose layers at entry point with Layer.provideMerge; provide once via Effect.provide(appLayer)\n- Parameterized layer constructors: assign to module-level const before reuse (memoization by reference)\n\n## RULE 5 — Schema for all data\n- Schema.Class for records: class User extends Schema.Class<User>(\"User\")({ ...fields }) {}\n- Schema.TaggedClass for union variants, discriminate with Match.valueTags\n- Brand all domain primitives: Schema.String.pipe(Schema.brand(\"UserId\"))\n- Type extraction: type UserId = typeof UserId.Type\n- JSON: Schema.parseJson(MySchema) for encode/decode\n\n## RULE 6 — Schema.Config + config service layers\n- Schema.Config(\"ENV_VAR\", MySchema) for validated/branded config\n- Config.redacted(\"SECRET\") for secrets (auto-hidden in logs)\n- Group related config into a single Context.Tag service with layer + testLayer\n\n## RULE 7 — Resilience via pipe\n- Chain: Effect.timeout, Effect.retry(Schedule.exponential(...).pipe(Schedule.compose(Schedule.recurs(n)))), Effect.tap, Effect.withSpan\n- Apply as .pipe() instrumentation on effects\n\n## RULE 8 — @effect/vitest for testing\n- it.effect(\"name\", () => Effect.gen(function* () { ... }).pipe(Effect.provide(Svc.testLayer)))\n- it.layer(Svc.testLayer)(\"suite\", (it) => { it.effect(...) }) for shared expensive resources\n- Test layers: Layer.sync(Tag, () => Tag.of({ ...in-memory impl }))\n\n## RULE 9 — Service-driven development workflow\n1. Sketch leaf service Tags (contracts, no impl)\n2. Write orchestration (higher-level services yield* leaf tags — compiles immediately)\n3. Implement leaf Layers\n4. Wire at entry point (compose into appLayer, provide once)\n\n## TypeScript Config (non-negotiable)\n- target: ES2022, module: NodeNext, moduleDetection: force\n- verbatimModuleSyntax: true, rewriteRelativeImportExtensions: true\n- strict: true, exactOptionalPropertyTypes: true\n- noUnusedLocals: true, noImplicitOverride: true\n- declarationMap: true, sourceMap: true, skipLibCheck: true\n\n\n# Effect-TS Quick Reference\n\n## Imports\nimport { Effect, Layer, Context, Schema, Config, Schedule, Match, Redacted } from \"effect\"\nimport { HttpClient, HttpClientResponse } from \"@effect/platform\"\nimport { it, expect } from \"@effect/vitest\"\n\n## Type Signatures\nEffect<A, E, R>  A=success  E=typed-error  R=required-services\nSchema.Class<T>(\"Tag\")({ field: Schema.String })  — branded record\nSchema.TaggedError<T>()(\"Tag\", { field: Schema.X })  — typed error\nSchema.TaggedClass<T>()(\"Tag\", { field: Schema.X })  — tagged variant\nContext.Tag(\"@scope/Name\")<Tag, Interface>()  — service tag\nLayer.effect(Tag, Effect.gen(...))  — service impl\nLayer.sync(Tag, () => Tag.of({...}))  — sync/test impl\nLayer.succeed(Tag, Tag.of({...}))  — constant impl\n\n## Effect Primitives\nEffect.succeed(value)             pure value\nEffect.fail(error)                typed error (E channel)\nEffect.sync(() => expr)           wrap sync side-effect\nEffect.promise(() => fetch(...))  wrap Promise\nEffect.die(defect)                unrecoverable defect\nEffect.orDie                      promote E to defect\nEffect.logInfo(msg)               structured log\nEffect.logError(msg, cause)       error log\nEffect.runPromise(effect)         run at entry (async)\nEffect.runSync(effect)            run at entry (sync)\n\n## Generators\nEffect.gen(function* () { const x = yield* someEffect; return x })\nEffect.fn(\"name\")(function* (arg: T) { ... })  — named + traced\nEffect.fn(\"name\")(function* (...) { ... }, flow(Effect.retry(...), Effect.timeout(...)))  — with transform\n\n## .pipe() Combinators\nEffect.timeout(\"2 seconds\")\nEffect.retry(Schedule.exponential(\"100 millis\").pipe(Schedule.compose(Schedule.recurs(3))))\nEffect.tap((a) => Effect.logInfo(...))\nEffect.withSpan(\"spanName\")\nEffect.annotateCurrentSpan(\"key\", value)\nEffect.catchTag(\"ErrorTag\", (e) => fallback)\nEffect.catchAll((e) => fallback)\nEffect.provide(layer)\nEffect.orDie\n\n## Schema\nconst UserId = Schema.String.pipe(Schema.brand(\"UserId\"))\ntype UserId = typeof UserId.Type\nSchema.Config(\"ENV_VAR\", MySchema)  — validated config\nConfig.redacted(\"SECRET\")  — secrets (logs as <redacted>)\nSchema.parseJson(MySchema)  — JSON codec\nSchema.decodeUnknown(schema)(input)  — decode\nSchema.encode(schema)(value)  — encode\n\n## tsconfig compilerOptions (required)\ntarget: ES2022, module: NodeNext, moduleDetection: force,\nverbatimModuleSyntax: true, rewriteRelativeImportExtensions: true,\nstrict: true, exactOptionalPropertyTypes: true,\nnoUnusedLocals: true, noImplicitOverride: true,\ndeclarationMap: true, sourceMap: true, skipLibCheck: true\n\n\n# Effect-First TypeScript — Code Examples\n\n## Effect.fn — basic\n\n    import { Effect } from \"effect\"\n\n    const processUser = Effect.fn(\"processUser\")(function* (userId: string) {\n      const user = yield* getUser(userId)\n      return yield* processData(user)\n    })\n\n## Effect.fn — with retry transform\n\n    import { Effect, Schedule, flow } from \"effect\"\n\n    const fetchWithRetry = Effect.fn(\"fetchWithRetry\")(\n      function* (url: string) {\n        return yield* fetchData(url)\n      },\n      flow(\n        Effect.retry(Schedule.exponential(\"100 millis\").pipe(Schedule.compose(Schedule.recurs(3)))),\n        Effect.timeout(\"5 seconds\")\n      )\n    )\n\n## Effect.gen — sequencing\n\n    import { Effect } from \"effect\"\n\n    const program = Effect.gen(function* () {\n      const data = yield* fetchData\n      yield* Effect.logInfo(`Processing: ${data}`)\n      return yield* processData(data)\n    })\n\n## TaggedError — definition\n\n    import { Schema } from \"effect\"\n\n    class UserNotFoundError extends Schema.TaggedError<UserNotFoundError>()(\n      \"UserNotFoundError\",\n      { id: Schema.String }\n    ) {}\n\n    class RateLimitError extends Schema.TaggedError<RateLimitError>()(\n      \"RateLimitError\",\n      { retryAfter: Schema.Number }\n    ) {}\n\n## TaggedError — recovery\n\n    const result = program.pipe(\n      Effect.catchTag(\"UserNotFoundError\", (e) => Effect.succeed(defaultUser)),\n      Effect.catchTag(\"RateLimitError\", (e) => Effect.fail(new FatalError({ cause: e })))\n    )\n\n    const safe = program.pipe(\n      Effect.catchAll((error) => Effect.gen(function* () {\n        yield* Effect.logError(\"Error\", error)\n        return fallback\n      }))\n    )\n\n## Service — Context.Tag definition\n\n    import { Context, Effect } from \"effect\"\n\n    class Database extends Context.Tag(\"@app/Database\")<\n      Database,\n      {\n        readonly query: (sql: string) => Effect.Effect<unknown[]>\n        readonly execute: (sql: string) => Effect.Effect<void>\n      }\n    >() {}\n\n## Service — Layer implementation with dependencies\n\n    import { Context, Effect, Layer } from \"effect\"\n\n    class Users extends Context.Tag(\"@app/Users\")<\n      Users,\n      {\n        readonly findById: (id: UserId) => Effect.Effect<User, UserNotFoundError>\n      }\n    >() {\n      static readonly layer = Layer.effect(\n        Users,\n        Effect.gen(function* () {\n          const db = yield* Database\n          const analytics = yield* Analytics\n\n          const findById = Effect.fn(\"Users.findById\")(function* (id: UserId) {\n            yield* analytics.track(\"user.find\", { id })\n            const rows = yield* db.query(`SELECT * FROM users WHERE id = '${id}'`)\n            if (rows.length === 0) return yield* new UserNotFoundError({ id })\n            return User.make(rows[0] as any)\n          })\n\n          return Users.of({ findById })\n        })\n      )\n    }\n\n## Schema — Class with branded ID\n\n    import { Schema } from \"effect\"\n\n    const UserId = Schema.String.pipe(Schema.brand(\"UserId\"))\n    type UserId = typeof UserId.Type\n\n    class User extends Schema.Class<User>(\"User\")({\n      id: UserId,\n      name: Schema.String,\n      email: Schema.String,\n      createdAt: Schema.Date,\n    }) {\n      get displayName() { return `${this.name} (${this.email})` }\n    }\n\n## Schema — branded primitives\n\n    const Email = Schema.String.pipe(Schema.brand(\"Email\"))\n    type Email = typeof Email.Type\n\n    const Port = Schema.Int.pipe(Schema.between(1, 65535), Schema.brand(\"Port\"))\n    type Port = typeof Port.Type\n\n## Schema — tagged union + Match\n\n    import { Match, Schema } from \"effect\"\n\n    class Success extends Schema.TaggedClass<Success>()(\"Success\", { value: Schema.Number }) {}\n    class Failure extends Schema.TaggedClass<Failure>()(\"Failure\", { error: Schema.String }) {}\n\n    const Result = Schema.Union(Success, Failure)\n    type Result = typeof Result.Type\n\n    const render = (r: Result) =>\n      Match.valueTags(r, {\n        Success: ({ value }) => `Got: ${value}`,\n        Failure: ({ error }) => `Error: ${error}`,\n      })\n\n## Schema — JSON encode/decode\n\n    const MoveFromJson = Schema.parseJson(Move)\n\n    // decode from JSON string\n    const move = yield* Schema.decodeUnknown(MoveFromJson)(jsonString)\n\n    // encode to JSON string\n    const json = yield* Schema.encode(MoveFromJson)(move)\n\n## Config — service layer with redacted secrets\n\n    import { Config, Context, Effect, Layer, Redacted, Schema } from \"effect\"\n\n    const Port = Schema.NumberFromString.pipe(Schema.int(), Schema.between(1, 65535), Schema.brand(\"Port\"))\n    type Port = typeof Port.Type\n\n    class AppConfig extends Context.Tag(\"@app/AppConfig\")<\n      AppConfig,\n      {\n        readonly port: Port\n        readonly apiKey: Redacted.Redacted\n        readonly env: \"development\" | \"staging\" | \"production\"\n      }\n    >() {\n      static readonly layer = Layer.effect(\n        AppConfig,\n        Effect.gen(function* () {\n          const port   = yield* Schema.Config(\"PORT\", Port)\n          const apiKey = yield* Config.redacted(\"API_KEY\")\n          const env    = yield* Schema.Config(\"ENV\", Schema.Literal(\"development\", \"staging\", \"production\"))\n          return AppConfig.of({ port, apiKey, env })\n        })\n      )\n\n      static readonly testLayer = Layer.succeed(AppConfig, AppConfig.of({\n        port: Port.make(3000),\n        apiKey: Redacted.make(\"test-key\"),\n        env: \"development\",\n      }))\n    }\n\n## Resilience — retry, timeout, span\n\n    import { Effect, Schedule } from \"effect\"\n\n    const retryPolicy = Schedule.exponential(\"100 millis\").pipe(\n      Schedule.compose(Schedule.recurs(3))\n    )\n\n    const resilient = callExternalApi.pipe(\n      Effect.timeout(\"2 seconds\"),\n      Effect.retry(retryPolicy),\n      Effect.timeout(\"10 seconds\"),\n      Effect.tap((data) => Effect.logInfo(`Fetched: ${data}`)),\n      Effect.withSpan(\"callExternalApi\")\n    )\n\n## Testing — per-test layer (preferred)\n\n    import { expect, it } from \"@effect/vitest\"\n    import { Effect } from \"effect\"\n\n    it.effect(\"creates a user\", () =>\n      Effect.gen(function* () {\n        const users = yield* Users\n        const user = yield* users.findById(UserId.make(\"u-1\"))\n        expect(user.name).toBe(\"Alice\")\n      }).pipe(Effect.provide(Users.testLayer))\n    )\n\n## Testing — suite-shared layer\n\n    it.layer(Users.testLayer)(\"users suite\", (it) => {\n      it.effect(\"finds user\", () => Effect.gen(function* () {\n        const users = yield* Users\n        expect(yield* users.findById(UserId.make(\"u-1\"))).toBeDefined()\n      }))\n    })\n\n## Testing — in-memory test layer\n\n    static readonly testLayer = Layer.sync(Users, () => {\n      const store = new Map([[\"u-1\", User.make({ id: UserId.make(\"u-1\"), name: \"Alice\", email: \"a@example.com\", createdAt: new Date() })]])\n      return Users.of({\n        findById: (id) => Effect.succeed(store.get(id)!),\n      })\n    })\n\n## Layer composition — entry point\n\n    import { Layer, Effect } from \"effect\"\n\n    const dbLayer = Postgres.layer({ url: \"postgres://localhost/mydb\", poolSize: 10 })\n\n    const appLayer = UsersLayer.pipe(\n      Layer.provideMerge(dbLayer),\n      Layer.provideMerge(AnalyticsLayer),\n      Layer.provideMerge(ConfigLayer)\n    )\n\n    Effect.runPromise(program.pipe(Effect.provide(appLayer)))\n\n## Defect promotion — orDie at entry point\n\n    const main = Effect.gen(function* () {\n      const config = yield* loadConfig.pipe(Effect.orDie)\n      yield* startServer(config)\n    })\n\n\nWRONG: async function foo() { ... }\nRIGHT: const foo = Effect.fn(\"foo\")(function* () { ... })\n\nWRONG: try { ... } catch (e) { ... }\nRIGHT: Effect.catchTag / Effect.catchAll\n\nWRONG: throw new Error(\"not found\")\nRIGHT: yield* new UserNotFoundError({ id }) (Schema.TaggedError)\n\nWRONG: class MyError extends Error { ... }\nRIGHT: class MyError extends Schema.TaggedError<MyError>()(\"MyError\", { ... }) {}\n\nWRONG: Promise<T> as service method return type\nRIGHT: Effect.Effect<A, E> as service method return type\n\nWRONG: Calling Postgres.layer(...) in multiple places\nRIGHT: const dbLayer = Postgres.layer(...) — assign once, share reference\n\nWRONG: Scattered Effect.provide(...) throughout codebase\nRIGHT: Provide once at entry point via composed appLayer\n\nWRONG: Effect.provide inside service method implementations\nRIGHT: Layer composition handles all dependency wiring\n\nWRONG: Config.string(\"PORT\") for validated/branded values\nRIGHT: Schema.Config(\"PORT\", Port)\n\nWRONG: console.log(apiKey) or Config.string(\"SECRET\")\nRIGHT: Config.redacted(\"SECRET\") — logs as <redacted>\n\nWRONG: Raw string for domain IDs (userId: string)\nRIGHT: Schema.String.pipe(Schema.brand(\"UserId\"))\n\nWRONG: Plain generator function* for effectful code\nRIGHT: Effect.fn(\"name\")(function* (...) { ... }) for tracing + spans\n\nWRONG: Effect.gen without yield* (using .then or await)\nRIGHT: yield* inside Effect.gen(function* () { ... })\n\nWRONG: interface + manual tag for services\nRIGHT: class Db extends Context.Tag(\"@app/Db\")<Db, { ... }>() {}\n\nWRONG: Inline object literals for data models\nRIGHT: Schema.Class / Schema.TaggedClass for runtime-validated models\n\nWRONG: Union types via string literals or manual discriminants\nRIGHT: Schema.Union(VariantA, VariantB) + Match.valueTags\n\nWRONG: Mutable service interface properties\nRIGHT: readonly on all service interface properties\n\nWRONG: it(\"test\", async () => { ... }) with manual runPromise\nRIGHT: it.effect(\"test\", () => Effect.gen(function* () { ... }))\n\nWRONG: Writing full implementation before defining service contracts\nRIGHT: Sketch Context.Tag contracts first, implement layers after\n\n\n# Effect-First TypeScript — HTTP Server (HttpApi)\n\nPackage: @effect/platform (HttpApi, HttpApiBuilder, HttpApiEndpoint, HttpApiGroup, HttpApiMiddleware, HttpApiSecurity)\n\n## Imports\n\n    import {\n      HttpApi, HttpApiBuilder, HttpApiEndpoint, HttpApiGroup,\n      HttpApiMiddleware, HttpApiSecurity\n    } from \"@effect/platform\"\n\n## Step 1 — Define endpoints\n\n    import { HttpApiEndpoint, HttpApiGroup, HttpApi } from \"@effect/platform\"\n    import { Schema } from \"effect\"\n\n    class User extends Schema.Class<User>(\"User\")({\n      id: Schema.String,\n      name: Schema.String,\n    }) {}\n\n    class UserNotFound extends Schema.TaggedError<UserNotFound>()(\"UserNotFound\", {\n      id: Schema.String,\n    }) {}\n\n    class UsersGroup extends HttpApiGroup.make(\"users\")\n      .add(\n        HttpApiEndpoint.get(\"findById\", \"/users/:id\")\n          .setPath(Schema.Struct({ id: Schema.String }))\n          .addSuccess(User)\n          .addError(UserNotFound, { status: 404 })\n      )\n      .add(\n        HttpApiEndpoint.post(\"create\", \"/users\")\n          .setPayload(Schema.Struct({ name: Schema.NonEmptyString }))\n          .addSuccess(User, { status: 201 })\n      )\n      .prefix(\"/api\") {}\n\n    class MyApi extends HttpApi.make(\"myApi\").add(UsersGroup) {}\n\n\n## Step 2 — Implement handlers\n\n    import { HttpApiBuilder } from \"@effect/platform\"\n    import { Effect, Layer } from \"effect\"\n\n    const UsersGroupLive = HttpApiBuilder.group(MyApi, \"users\", (handlers) =>\n      handlers\n        .handle(\"findById\", ({ path }) =>\n          Effect.gen(function* () {\n            const users = yield* Users\n            return yield* users.findById(path.id)\n          })\n        )\n        .handle(\"create\", ({ payload }) =>\n          Effect.gen(function* () {\n            const users = yield* Users\n            return yield* users.create(payload.name)\n          })\n        )\n    )\n\n\n## Step 3 — Serve\n\n    import { NodeHttpServer } from \"@effect/platform-node\"\n    import { HttpApiBuilder } from \"@effect/platform\"\n    import { Layer, Effect } from \"effect\"\n    import { createServer } from \"node:http\"\n\n    const ApiLive = HttpApiBuilder.api(MyApi).pipe(\n      Layer.provide(UsersGroupLive),\n      Layer.provide(Users.layer)\n    )\n\n    const ServerLive = NodeHttpServer.layer(createServer, { port: 3000 })\n\n    const app = HttpApiBuilder.serve().pipe(\n      Layer.provide(ServerLive),\n      Layer.provide(ApiLive)\n    )\n\n    Layer.launch(app).pipe(Effect.runPromise)\n\n\n## HttpApi key constructors\n\n    HttpApi.make(id)                                — create API\n    HttpApiGroup.make(id)                           — create group\n    HttpApiEndpoint.get(name, path)                 — GET endpoint\n    HttpApiEndpoint.post(name, path)                — POST endpoint\n    HttpApiEndpoint.put(name, path)                 — PUT endpoint\n    HttpApiEndpoint.del(name, path)                 — DELETE endpoint\n    HttpApiEndpoint.patch(name, path)               — PATCH endpoint\n\n## Endpoint schema methods (chainable)\n\n    .setPath(Schema.Struct({ id: Schema.String }))  — path params\n    .setPayload(schema)                              — request body (POST/PUT/PATCH)\n    .setUrlParams(schema)                            — query string params (GET)\n    .setHeaders(schema)                              — required headers\n    .addSuccess(schema, { status: 200 })             — success response\n    .addError(schema, { status: 404 })               — error response\n    .prefix(\"/v1\")                                   — path prefix\n\n## Group / API composition\n\n    group.add(endpoint)                              — add endpoint to group\n    group.addError(schema, { status })               — shared error for all endpoints\n    group.prefix(\"/api\")                             — prefix all routes\n    api.add(group)                                   — add group to api\n    api.addError(schema, { status })                 — global error\n\n## Builder\n\n    HttpApiBuilder.api(MyApi)                        — Layer<HttpApi.Api>\n    HttpApiBuilder.group(api, name, build)           — Layer for a group\n    HttpApiBuilder.serve()                           — Layer that starts server\n    HttpApiBuilder.toWebHandler(layer)               — { handler, dispose } for Cloudflare/Bun\n\n\n## Security\n\n    import { HttpApiSecurity, HttpApiMiddleware } from \"@effect/platform\"\n\n    class AuthMiddleware extends HttpApiMiddleware.Tag<AuthMiddleware>()(\"AuthMiddleware\", {\n      provides: CurrentUser,\n      security: { bearer: HttpApiSecurity.bearer },\n    }) {}\n\n    // Apply to group\n    class SecureGroup extends HttpApiGroup.make(\"secure\")\n      .middleware(AuthMiddleware)\n      .add(...) {}\n\n    // Implement middleware\n    const AuthMiddlewareLive = Layer.effect(AuthMiddleware, Effect.gen(function* () {\n      return AuthMiddleware.of({\n        bearer: (token) => Effect.gen(function* () {\n          // validate token, return CurrentUser\n        })\n      })\n    }))\n\n\n## Anti-patterns\n\nWRONG: Manual HttpRouter.get/post for typed APIs\nRIGHT: HttpApi + HttpApiEndpoint for schema-validated, auto-documented endpoints\n\nWRONG: Parsing request body manually in handlers\nRIGHT: .setPayload(schema) — decoded and validated before handler runs\n\nWRONG: Returning HttpServerResponse from handlers\nRIGHT: Return domain types; framework encodes via success/error schemas\n\nWRONG: Implementing auth checks inside each handler\nRIGHT: HttpApiMiddleware + HttpApiSecurity applied to group or api\n\n\n# Effect-First TypeScript — HTTP Client\n\nPackage: @effect/platform (HttpClient, HttpClientRequest, HttpClientResponse, HttpClientError)\n\n## Imports\n\n    import { HttpClient, HttpClientRequest, HttpClientResponse, FetchHttpClient } from \"@effect/platform\"\n    import { NodeHttpClient } from \"@effect/platform-node\"\n    import { Effect, Schema } from \"effect\"\n\n## Basic GET\n\n    const fetchUser = Effect.fn(\"fetchUser\")(function* (id: string) {\n      const client = yield* HttpClient.HttpClient\n      const response = yield* client.get(`https://api.example.com/users/${id}`)\n      return yield* HttpClientResponse.schemaBodyJson(User)(response)\n    })\n\n    // Provide the client layer\n    fetchUser(\"u-1\").pipe(Effect.provide(FetchHttpClient.layer))\n\n## POST with JSON body\n\n    const createUser = Effect.fn(\"createUser\")(function* (name: string) {\n      const client = yield* HttpClient.HttpClient\n      const request = HttpClientRequest.post(\"https://api.example.com/users\").pipe(\n        HttpClientRequest.jsonBody({ name })\n      )\n      const response = yield* client.execute(request)\n      return yield* HttpClientResponse.schemaBodyJson(User)(response)\n    })\n\n## HttpApiClient — typed client from HttpApi definition\n\n    import { HttpApiClient } from \"@effect/platform\"\n\n    const program = Effect.gen(function* () {\n      const client = yield* HttpApiClient.make(MyApi, {\n        baseUrl: \"https://api.example.com\",\n      })\n      const user = yield* client.users.findById({ path: { id: \"u-1\" } })\n    })\n\n## Resilience — retry + timeout\n\n    const resilientFetch = fetchUser(\"u-1\").pipe(\n      Effect.retry(Schedule.exponential(\"200 millis\").pipe(Schedule.compose(Schedule.recurs(3)))),\n      Effect.timeout(\"10 seconds\"),\n      Effect.withSpan(\"fetchUser\")\n    )\n\n\n## Key types\n\n    HttpClient.HttpClient                — Context.Tag for the client service\n    HttpClientRequest.HttpClientRequest  — immutable request description\n    HttpClientResponse.HttpClientResponse — response with schema decoding\n    HttpClientError.HttpClientError      — typed error (RequestError | ResponseError)\n\n## Client methods\n\n    client.get(url, options?)            — GET request\n    client.post(url, options?)           — POST request\n    client.put(url, options?)            — PUT request\n    client.del(url, options?)            — DELETE request\n    client.patch(url, options?)          — PATCH request\n    client.head(url, options?)           — HEAD request\n    client.execute(request)              — execute arbitrary request\n\n## Response decoding\n\n    HttpClientResponse.schemaBodyJson(schema)(response)   — decode JSON body\n    HttpClientResponse.text(response)                     — body as string\n    HttpClientResponse.json(response)                     — body as unknown JSON\n    HttpClientResponse.stream(response)                   — body as Stream<Uint8Array>\n\n## Layers\n\n    FetchHttpClient.layer                — uses globalThis.fetch (browser, Cloudflare Workers, Bun)\n    NodeHttpClient.layer                 — uses Node.js undici\n\n## Anti-patterns\n\nWRONG: fetch(url).then(r => r.json())\nRIGHT: client.get(url) |> HttpClientResponse.schemaBodyJson(Schema)\n\nWRONG: Manual error handling for HTTP status codes\nRIGHT: HttpClient errors are typed; use Effect.catchTag(\"ResponseError\", ...)\n\nWRONG: Hardcoding fetch in service implementations\nRIGHT: Depend on HttpClient.HttpClient tag; provide FetchHttpClient.layer or NodeHttpClient.layer\n\nWRONG: Building typed API clients by hand\nRIGHT: HttpApiClient.make(MyApi) generates fully typed client from HttpApi definition\n\n\n# Effect-First TypeScript — SQL (@effect/sql)\n\n@effect/sql provides a tagged template literal SQL client, schema-validated queries, batched resolvers, and a Model system for domain objects with insert/update/json variants.\n\nPackage: @effect/sql (SqlClient, SqlSchema, SqlResolver, Model, Migrator)\nDB adapters: @effect/sql-pg, @effect/sql-sqlite-node, @effect/sql-mysql2, @effect/sql-mssql\n\n\n## Imports\n\n    import { SqlClient, SqlSchema, SqlResolver, Model } from \"@effect/sql\"\n    import { PgClient } from \"@effect/sql-pg\"        // or SqliteClient, etc.\n    import { Effect, Schema } from \"effect\"\n\n\n## SqlClient — tagged template queries\n\n    const program = Effect.gen(function* () {\n      const sql = yield* SqlClient.SqlClient\n\n      // select — returns ReadonlyArray<unknown>\n      const rows = yield* sql`SELECT * FROM users WHERE id = ${userId}`\n\n      // insert\n      yield* sql`INSERT INTO users ${sql.insert({ id, name, email })}`\n\n      // update\n      yield* sql`UPDATE users SET ${sql.update({ name, email })} WHERE id = ${id}`\n\n      // transactions\n      yield* sql.withTransaction(\n        Effect.gen(function* () {\n          yield* sql`INSERT INTO orders ${sql.insert(order)}`\n          yield* sql`UPDATE inventory SET qty = qty - 1 WHERE id = ${itemId}`\n        })\n      )\n    })\n\n\n## SqlSchema — validated queries\n\n    import { SqlClient, SqlSchema } from \"@effect/sql\"\n    import { Effect, Schema } from \"effect\"\n\n    const findUserById = SqlSchema.findOne({\n      Request: Schema.String,\n      Result: User,\n      execute: (id) => Effect.gen(function* () {\n        const sql = yield* SqlClient.SqlClient\n        return yield* sql`SELECT * FROM users WHERE id = ${id}`\n      }),\n    })\n\n    // SqlSchema variants:\n    // SqlSchema.findAll    — returns ReadonlyArray<A>\n    // SqlSchema.findOne    — returns Option<A>\n    // SqlSchema.single     — returns A (throws NoSuchElementException if missing)\n    // SqlSchema.void       — discards result\n\n\n## Model — domain objects with variants\n\n    import { Model } from \"@effect/sql\"\n    import { Schema } from \"effect\"\n\n    const GroupId = Schema.Number.pipe(Schema.brand(\"GroupId\"))\n\n    class Group extends Model.Class<Group>(\"Group\")({\n      id: Model.Generated(GroupId),\n      name: Schema.NonEmptyTrimmedString,\n      createdAt: Model.DateTimeInsertFromDate,\n      updatedAt: Model.DateTimeUpdateFromDate,\n    }) {}\n\n    // Variants auto-generated:\n    // Group            — select schema (all fields)\n    // Group.insert     — insert schema (id omitted, createdAt auto)\n    // Group.update     — update schema (all optional, updatedAt auto)\n    // Group.json       — JSON API schema\n    // Group.jsonCreate — JSON create schema\n    // Group.jsonUpdate — JSON update schema\n\n    // Model field helpers:\n    // Model.Generated(schema)              — omit from insert\n    // Model.GeneratedByApp(schema)         — required in insert, not from DB\n    // Model.DateTimeInsertFromDate         — auto DateTime on insert\n    // Model.DateTimeUpdateFromDate         — auto DateTime on update\n    // Model.Sensitive(schema)              — omit from json variants\n    // Model.FieldOption(schema)            — Option<A> field\n    // Model.JsonFromString(schema)         — JSON stored as string column\n\n\n## SqlResolver — batched queries with Effect Request\n\n    const UserById = SqlResolver.findById(\"UserById\", {\n      Id: UserId,\n      Result: User,\n      ResultId: (user) => user.id,\n      execute: (ids) => Effect.gen(function* () {\n        const sql = yield* SqlClient.SqlClient\n        return yield* sql`SELECT * FROM users WHERE id IN ${sql.in(ids)}`\n      }),\n    })\n\n    // Use:\n    const user = yield* UserById.execute(userId)\n\n    // SqlResolver variants:\n    // SqlResolver.findById   — returns Option<A>, keyed by ID\n    // SqlResolver.ordered    — results match request order 1:1\n    // SqlResolver.grouped    — group results by key (1:many)\n    // SqlResolver.void       — batched writes, no result\n\n\n## Model.makeRepository — CRUD from Model\n\n    const GroupRepo = Model.makeRepository(Group, {\n      tableName: \"groups\",\n      spanPrefix: \"GroupRepo\",\n      idColumn: \"id\",\n    })\n\n    // Provides: findById, insert, update, delete, etc.\n\n\n## Layers (provide at entry point)\n\n    // PostgreSQL\n    import { PgClient } from \"@effect/sql-pg\"\n    const DbLive = PgClient.layer({ url: \"postgres://localhost/mydb\" })\n\n    // SQLite\n    import { SqliteClient } from \"@effect/sql-sqlite-node\"\n    const DbLive = SqliteClient.layer({ filename: \"./data.db\" })\n\n    // Always assign to a const — memoization by reference\n    Effect.runPromise(program.pipe(Effect.provide(DbLive)))\n\n\n## Anti-patterns\n\nWRONG: String concatenation for SQL queries\nRIGHT: Tagged template: sql`SELECT * FROM users WHERE id = ${id}` (auto-parameterized)\n\nWRONG: Manual row-to-object mapping\nRIGHT: SqlSchema.findAll/findOne with Schema for validated decoding\n\nWRONG: N+1 queries in loops\nRIGHT: SqlResolver.findById / SqlResolver.grouped for automatic batching\n\nWRONG: Separate type definitions for insert vs select\nRIGHT: Model.Class generates all variants (select, insert, update, json) from one definition\n\nWRONG: Manual transaction begin/commit/rollback\nRIGHT: sql.withTransaction(effect) handles commit/rollback automatically\n\n\n# Effect-First TypeScript — CLI & Commands\n\nEffect provides two distinct capabilities:\n1. Command execution — run external processes via @effect/platform Command\n2. CLI argument parsing — use effect Config + Schema.Config for argv/env, or @effect/cli for full CLI apps\n\n\n## Imports\n\n    import { Command, CommandExecutor } from \"@effect/platform\"\n    import { NodeCommandExecutor, NodeFileSystem } from \"@effect/platform-node\"\n    import { Effect, Stream } from \"effect\"\n\n\n## Running external commands\n\n    const listFiles = Effect.gen(function* () {\n      // Simple: get stdout as string\n      const output = yield* Command.make(\"ls\", \"-la\").pipe(Command.string)\n\n      // With options\n      const result = yield* Command.make(\"git\", \"status\")\n        .pipe(\n          Command.workingDirectory(\"/path/to/repo\"),\n          Command.env({ GIT_AUTHOR_NAME: \"bot\" }),\n          Command.string\n        )\n\n      // Exit code only\n      const code = yield* Command.make(\"npm\", \"test\").pipe(Command.exitCode)\n\n      return output\n    })\n\n    // Provide the executor\n    listFiles.pipe(\n      Effect.provide(NodeCommandExecutor.layer),\n      Effect.provide(NodeFileSystem.layer)\n    )\n\n\n## Streaming output\n\n    // Stream stdout line by line\n    const logStream = Command.make(\"tail\", \"-f\", \"/var/log/app.log\").pipe(\n      Command.streamLines\n    )\n\n    // Process as a stream\n    const program = logStream.pipe(\n      Stream.filter((line) => line.includes(\"ERROR\")),\n      Stream.tap((line) => Effect.logError(line)),\n      Stream.runDrain\n    )\n\n    // Raw byte stream\n    const bytes = Command.make(\"cat\", \"file.bin\").pipe(Command.stream)\n\n\n## Piping commands\n\n    const pipeline = Command.make(\"cat\", \"data.csv\").pipe(\n      Command.pipeTo(Command.make(\"grep\", \"error\")),\n      Command.pipeTo(Command.make(\"wc\", \"-l\")),\n      Command.string\n    )\n\n\n## Process with stdin\n\n    const withInput = Command.make(\"wc\", \"-w\").pipe(\n      Command.feed(\"hello world this is a test\"),\n      Command.string\n    )\n\n\n## Command API reference\n\n    Command.make(cmd, ...args)           — create command\n    Command.string(cmd)                  — run, return stdout as string\n    Command.lines(cmd)                   — run, return stdout as string[]\n    Command.exitCode(cmd)                — run, return exit code\n    Command.stream(cmd)                  — stdout as Stream<Uint8Array>\n    Command.streamLines(cmd)             — stdout as Stream<string>\n    Command.start(cmd)                   — start Process (stdin/stdout/stderr access)\n    Command.pipeTo(target)               — pipe stdout to another command\n    Command.feed(input)                  — feed string to stdin\n    Command.workingDirectory(path)       — set cwd\n    Command.env(record)                  — set env vars\n    Command.runInShell(shell)            — run via shell (boolean | string)\n\n## Layers\n\n    NodeCommandExecutor.layer            — Node.js process execution\n    NodeFileSystem.layer                 — required by NodeCommandExecutor\n\n\n## CLI argument parsing with Config\n\nFor simple CLIs, use effect’s Config module (reads from env + argv):\n\n    import { Config, Effect, Schema } from \"effect\"\n\n    const program = Effect.gen(function* () {\n      const port = yield* Schema.Config(\"PORT\", Schema.NumberFromString.pipe(\n        Schema.int(), Schema.between(1, 65535)\n      ))\n      const verbose = yield* Config.withDefault(Config.boolean(\"VERBOSE\"), false)\n      const dbUrl = yield* Config.redacted(\"DATABASE_URL\")\n      yield* Effect.logInfo(`Starting on port ${port}`)\n    })\n\n\n## Anti-patterns\n\nWRONG: child_process.exec(cmd, callback)\nRIGHT: Command.make(cmd).pipe(Command.string)\n\nWRONG: Manually parsing stdout string into lines\nRIGHT: Command.streamLines(cmd) returns Stream<string>\n\nWRONG: process.env.PORT with manual parseInt\nRIGHT: Schema.Config(\"PORT\", Schema.NumberFromString) with validation\n\nWRONG: Forgetting to provide CommandExecutor layer\nRIGHT: Effect.provide(NodeCommandExecutor.layer) + Effect.provide(NodeFileSystem.layer)\n\n\n# Effect-First TypeScript — Streams\n\nStream<A, E, R> is a pull-based, backpressured sequence of values.\n\nPackage: effect (Stream, Sink, Channel)\n\n## Imports\n\n    import { Stream, Sink, Chunk, Effect, Schedule } from \"effect\"\n\n## Creating streams\n\n    // From values\n    Stream.make(1, 2, 3)\n    Stream.fromIterable([1, 2, 3])\n    Stream.range(1, 100)\n    Stream.empty\n\n    // From Effect (single value stream)\n    Stream.fromEffect(fetchUser(id))\n\n    // Repeated effect\n    Stream.repeatEffect(readSensor)\n    Stream.repeatEffectWithSchedule(pollApi, Schedule.spaced(\"5 seconds\"))\n\n    // Pagination\n    Stream.paginate(initialCursor, (cursor) => {\n      const page = fetchPage(cursor)\n      return [page.items, Option.fromNullable(page.nextCursor)]\n    })\n\n    // From async\n    Stream.fromAsyncIterable(asyncIter, (e) => new MyError({ cause: e }))\n    Stream.async((emit) => { /* push values via emit */ })\n\n    // Infinite\n    Stream.iterate(0, (n) => n + 1)\n    Stream.repeatValue(\"tick\")\n\n\n## Transforming streams\n\n    stream.pipe(\n      Stream.map((x) => x * 2),\n      Stream.filter((x) => x > 10),\n      Stream.take(5),\n      Stream.drop(2),\n      Stream.flatMap((x) => Stream.make(x, x + 1)),\n      Stream.mapEffect((x) => processItem(x)),\n      Stream.tap((x) => Effect.logInfo(`Processing: ${x}`)),\n      Stream.scan(0, (acc, x) => acc + x),\n    )\n\n    // Chunked operations (batch-efficient)\n    stream.pipe(\n      Stream.mapChunks((chunk) => Chunk.map(chunk, transform)),\n      Stream.grouped(100),           // group into chunks of 100\n      Stream.debounce(\"500 millis\"), // debounce emissions\n    )\n\n\n## Consuming streams\n\n    // Collect all (careful with large streams)\n    const items = yield* Stream.runCollect(stream)  // Chunk<A>\n\n    // Fold\n    const sum = yield* Stream.runFold(stream, 0, (acc, x) => acc + x)\n\n    // ForEach (side effects)\n    yield* Stream.runForEach(stream, (item) => processItem(item))\n\n    // Drain (discard values, run for effects)\n    yield* Stream.runDrain(stream)\n\n    // Count\n    const n = yield* Stream.runCount(stream)\n\n    // With Sink\n    yield* Stream.run(stream, Sink.collectAll())\n    yield* Stream.run(stream, Sink.foldLeft(0, (acc, x) => acc + x))\n\n\n## Combining streams\n\n    // Merge (interleave, concurrent)\n    Stream.merge(streamA, streamB)\n    Stream.mergeAll([streamA, streamB, streamC], { concurrency: 3 })\n\n    // Concat (sequential)\n    Stream.concat(streamA, streamB)\n\n    // Zip (pair elements)\n    Stream.zip(streamA, streamB)          // Stream<[A, B]>\n    Stream.zipWith(streamA, streamB, (a, b) => a + b)\n\n\n## Error handling\n\n    stream.pipe(\n      Stream.catchAll((e) => Stream.make(fallbackValue)),\n      Stream.catchTag(\"NetworkError\", (e) => Stream.empty),\n      Stream.retry(Schedule.exponential(\"1 second\")),\n    )\n\n\n## Sinks (stream consumers)\n\n    Sink.collectAll()                    — collect into Chunk<A>\n    Sink.foldLeft(init, f)               — fold without early termination\n    Sink.fold(init, contFn, f)           — fold with early termination\n    Sink.forEach(f)                      — side-effect per element\n    Sink.head                            — first element as Option<A>\n    Sink.last                            — last element as Option<A>\n    Sink.count                           — count elements\n    Sink.sum                             — sum numbers\n    Sink.take(n)                         — take first n into Chunk<A>\n\n\n## Common patterns\n\n    // Polling with schedule\n    const poller = Stream.repeatEffectWithSchedule(\n      checkStatus,\n      Schedule.spaced(\"10 seconds\")\n    ).pipe(\n      Stream.takeUntil((status) => status === \"complete\")\n    )\n\n    // Batched processing\n    const batchProcessor = eventStream.pipe(\n      Stream.grouped(50),\n      Stream.mapEffect((batch) => processBatch(Chunk.toReadonlyArray(batch)),\n        { concurrency: 3 }\n      ),\n      Stream.runDrain\n    )\n\n\n## Anti-patterns\n\nWRONG: Collecting unbounded stream into array\nRIGHT: Stream.runForEach or Stream.runFold for bounded consumption\n\nWRONG: for await (const x of asyncIter) with manual error handling\nRIGHT: Stream.fromAsyncIterable + Stream.mapEffect for typed errors\n\nWRONG: setInterval + mutable array for polling\nRIGHT: Stream.repeatEffectWithSchedule + Stream.takeUntil\n\nWRONG: Manual batching with counters\nRIGHT: Stream.grouped(n) + Stream.mapEffect with concurrency\n\nWRONG: Promise.all for concurrent stream processing\nRIGHT: Stream.mergeAll with concurrency option\n\n\n# Effect-First TypeScript — Concurrency\n\n## Imports\n\n    import { Effect, Fiber, FiberSet, FiberMap } from \"effect\"\n\n## Structured concurrency\n\n    // Run in parallel (all succeed or first error)\n    const result = yield* Effect.all([taskA, taskB, taskC], { concurrency: 2 })\n\n    // ForEach with concurrency + batching\n    yield* Effect.forEach(items, (item) => process(item), { concurrency: 5 })\n\n## Fork / join\n\n    const fiber = yield* Effect.fork(task)\n    const value = yield* Fiber.join(fiber)\n\n    // Fork and interrupt\n    const fiber = yield* Effect.fork(longRunning)\n    yield* Fiber.interrupt(fiber)\n\n    // Scoped fork (auto-interrupt on scope close)\n    const fiber = yield* Effect.forkScoped(task)\n    yield* Fiber.join(fiber)\n\n## Race\n\n    const fastest = yield* Effect.race(taskA, taskB)\n    const winner = yield* Effect.raceAll([taskA, taskB, taskC])\n\n## Fiber collections\n\n    const set = yield* FiberSet.make()\n    yield* FiberSet.run(set, taskA)\n    yield* FiberSet.run(set, taskB)\n    yield* FiberSet.join(set)\n\n    const map = yield* FiberMap.make()\n    yield* FiberMap.run(map, \"job-1\", taskA)\n    yield* FiberMap.run(map, \"job-2\", taskB)\n    yield* FiberMap.join(map, \"job-1\")\n\n## Interrupt\n\n    const fiber = yield* Effect.fork(task)\n    yield* Fiber.interrupt(fiber)\n    yield* Fiber.await(fiber)  // observe exit\n\n\n# Effect-First TypeScript — Resources & Scope\n\n## Imports\n\n    import { Effect, Layer, Scope, Pool, ScopedRef } from \"effect\"\n\n## acquireRelease\n\n    const file = yield* Effect.acquireRelease(\n      openFile(path),\n      (handle) => closeFile(handle)\n    )\n\n    const program = Effect.acquireUseRelease(\n      connectDb,\n      (db) => db.query(\"select * from users\"),\n      (db) => db.close\n    )\n\n## addFinalizer\n\n    const program = Effect.gen(function* () {\n      yield* Effect.addFinalizer(() => Effect.logInfo(\"cleanup\"))\n      return yield* doWork\n    })\n\n## Scope service\n\n    const scoped = Effect.scoped(\n      Effect.gen(function* () {\n        const scope = yield* Scope.Scope\n        return scope\n      })\n    )\n\n## Layer.scoped\n\n    class Connection extends Context.Tag(\"@app/Connection\")<\n      Connection,\n      { readonly query: (sql: string) => Effect.Effect<unknown[]> }\n    >() {}\n\n    const ConnectionLive = Layer.scoped(\n      Connection,\n      Effect.acquireRelease(connectDb, (db) => db.close)\n    )\n\n## Pools\n\n    const pool = yield* Pool.make({\n      acquire: connectDb,\n      size: 10,\n      timeToLive: \"10 minutes\",\n      concurrency: 2,\n    })\n\n    const db = yield* Pool.get(pool)\n\n## ScopedRef\n\n    const ref = yield* ScopedRef.fromAcquire(connectDb)\n    const db = yield* ScopedRef.get(ref)\n"
  },
  "moduleTextByName": {
    "rules": "# Effect-First TypeScript — Rules\n\n## RULE 1 — Effect.fn for all named effectful functions\n- Wrap every named effectful function (including nullary) with Effect.fn(\"name\")(function* (...) { ... })\n- Optional second arg transforms the whole effect (retry, timeout, etc.)\n- Never use async functions for effectful code\n\n## RULE 2 — Effect.gen for sequencing\n- Use Effect.gen(function* () { ... }) to sequence effects\n- yield* each Effect; return final value\n\n## RULE 3 — Schema.TaggedError for all errors\n- Every error: class MyError extends Schema.TaggedError<MyError>()(\"MyError\", { ...fields })\n- Recover with Effect.catchTag(\"Tag\", handler) or Effect.catchAll\n- E channel = domain failures callers handle (not found, validation, rate limit)\n- Defects (Effect.die / Effect.orDie) = bugs/invariant violations, handled at boundary only\n\n## RULE 4 — Context.Tag + Layer for all services\n- class Svc extends Context.Tag(\"@scope/Svc\")<Svc, { readonly method: (...) => Effect.Effect<A, E> }>() {}\n- Tag IDs globally unique (@scope/Name)\n- Service methods must have R = never; dependencies resolved via Layer, not method signatures\n- Implement via static layer = Layer.effect(Tag, Effect.gen(function* () { ... }))\n- Layer names: layer, testLayer, postgresLayer (camelCase + Layer suffix)\n- Compose layers at entry point with Layer.provideMerge; provide once via Effect.provide(appLayer)\n- Parameterized layer constructors: assign to module-level const before reuse (memoization by reference)\n\n## RULE 5 — Schema for all data\n- Schema.Class for records: class User extends Schema.Class<User>(\"User\")({ ...fields }) {}\n- Schema.TaggedClass for union variants, discriminate with Match.valueTags\n- Brand all domain primitives: Schema.String.pipe(Schema.brand(\"UserId\"))\n- Type extraction: type UserId = typeof UserId.Type\n- JSON: Schema.parseJson(MySchema) for encode/decode\n\n## RULE 6 — Schema.Config + config service layers\n- Schema.Config(\"ENV_VAR\", MySchema) for validated/branded config\n- Config.redacted(\"SECRET\") for secrets (auto-hidden in logs)\n- Group related config into a single Context.Tag service with layer + testLayer\n\n## RULE 7 — Resilience via pipe\n- Chain: Effect.timeout, Effect.retry(Schedule.exponential(...).pipe(Schedule.compose(Schedule.recurs(n)))), Effect.tap, Effect.withSpan\n- Apply as .pipe() instrumentation on effects\n\n## RULE 8 — @effect/vitest for testing\n- it.effect(\"name\", () => Effect.gen(function* () { ... }).pipe(Effect.provide(Svc.testLayer)))\n- it.layer(Svc.testLayer)(\"suite\", (it) => { it.effect(...) }) for shared expensive resources\n- Test layers: Layer.sync(Tag, () => Tag.of({ ...in-memory impl }))\n\n## RULE 9 — Service-driven development workflow\n1. Sketch leaf service Tags (contracts, no impl)\n2. Write orchestration (higher-level services yield* leaf tags — compiles immediately)\n3. Implement leaf Layers\n4. Wire at entry point (compose into appLayer, provide once)\n\n## TypeScript Config (non-negotiable)\n- target: ES2022, module: NodeNext, moduleDetection: force\n- verbatimModuleSyntax: true, rewriteRelativeImportExtensions: true\n- strict: true, exactOptionalPropertyTypes: true\n- noUnusedLocals: true, noImplicitOverride: true\n- declarationMap: true, sourceMap: true, skipLibCheck: true\n",
    "reference": "# Effect-TS Quick Reference\n\n## Imports\nimport { Effect, Layer, Context, Schema, Config, Schedule, Match, Redacted } from \"effect\"\nimport { HttpClient, HttpClientResponse } from \"@effect/platform\"\nimport { it, expect } from \"@effect/vitest\"\n\n## Type Signatures\nEffect<A, E, R>  A=success  E=typed-error  R=required-services\nSchema.Class<T>(\"Tag\")({ field: Schema.String })  — branded record\nSchema.TaggedError<T>()(\"Tag\", { field: Schema.X })  — typed error\nSchema.TaggedClass<T>()(\"Tag\", { field: Schema.X })  — tagged variant\nContext.Tag(\"@scope/Name\")<Tag, Interface>()  — service tag\nLayer.effect(Tag, Effect.gen(...))  — service impl\nLayer.sync(Tag, () => Tag.of({...}))  — sync/test impl\nLayer.succeed(Tag, Tag.of({...}))  — constant impl\n\n## Effect Primitives\nEffect.succeed(value)             pure value\nEffect.fail(error)                typed error (E channel)\nEffect.sync(() => expr)           wrap sync side-effect\nEffect.promise(() => fetch(...))  wrap Promise\nEffect.die(defect)                unrecoverable defect\nEffect.orDie                      promote E to defect\nEffect.logInfo(msg)               structured log\nEffect.logError(msg, cause)       error log\nEffect.runPromise(effect)         run at entry (async)\nEffect.runSync(effect)            run at entry (sync)\n\n## Generators\nEffect.gen(function* () { const x = yield* someEffect; return x })\nEffect.fn(\"name\")(function* (arg: T) { ... })  — named + traced\nEffect.fn(\"name\")(function* (...) { ... }, flow(Effect.retry(...), Effect.timeout(...)))  — with transform\n\n## .pipe() Combinators\nEffect.timeout(\"2 seconds\")\nEffect.retry(Schedule.exponential(\"100 millis\").pipe(Schedule.compose(Schedule.recurs(3))))\nEffect.tap((a) => Effect.logInfo(...))\nEffect.withSpan(\"spanName\")\nEffect.annotateCurrentSpan(\"key\", value)\nEffect.catchTag(\"ErrorTag\", (e) => fallback)\nEffect.catchAll((e) => fallback)\nEffect.provide(layer)\nEffect.orDie\n\n## Schema\nconst UserId = Schema.String.pipe(Schema.brand(\"UserId\"))\ntype UserId = typeof UserId.Type\nSchema.Config(\"ENV_VAR\", MySchema)  — validated config\nConfig.redacted(\"SECRET\")  — secrets (logs as <redacted>)\nSchema.parseJson(MySchema)  — JSON codec\nSchema.decodeUnknown(schema)(input)  — decode\nSchema.encode(schema)(value)  — encode\n\n## tsconfig compilerOptions (required)\ntarget: ES2022, module: NodeNext, moduleDetection: force,\nverbatimModuleSyntax: true, rewriteRelativeImportExtensions: true,\nstrict: true, exactOptionalPropertyTypes: true,\nnoUnusedLocals: true, noImplicitOverride: true,\ndeclarationMap: true, sourceMap: true, skipLibCheck: true\n",
    "examples": "# Effect-First TypeScript — Code Examples\n\n## Effect.fn — basic\n\n    import { Effect } from \"effect\"\n\n    const processUser = Effect.fn(\"processUser\")(function* (userId: string) {\n      const user = yield* getUser(userId)\n      return yield* processData(user)\n    })\n\n## Effect.fn — with retry transform\n\n    import { Effect, Schedule, flow } from \"effect\"\n\n    const fetchWithRetry = Effect.fn(\"fetchWithRetry\")(\n      function* (url: string) {\n        return yield* fetchData(url)\n      },\n      flow(\n        Effect.retry(Schedule.exponential(\"100 millis\").pipe(Schedule.compose(Schedule.recurs(3)))),\n        Effect.timeout(\"5 seconds\")\n      )\n    )\n\n## Effect.gen — sequencing\n\n    import { Effect } from \"effect\"\n\n    const program = Effect.gen(function* () {\n      const data = yield* fetchData\n      yield* Effect.logInfo(`Processing: ${data}`)\n      return yield* processData(data)\n    })\n\n## TaggedError — definition\n\n    import { Schema } from \"effect\"\n\n    class UserNotFoundError extends Schema.TaggedError<UserNotFoundError>()(\n      \"UserNotFoundError\",\n      { id: Schema.String }\n    ) {}\n\n    class RateLimitError extends Schema.TaggedError<RateLimitError>()(\n      \"RateLimitError\",\n      { retryAfter: Schema.Number }\n    ) {}\n\n## TaggedError — recovery\n\n    const result = program.pipe(\n      Effect.catchTag(\"UserNotFoundError\", (e) => Effect.succeed(defaultUser)),\n      Effect.catchTag(\"RateLimitError\", (e) => Effect.fail(new FatalError({ cause: e })))\n    )\n\n    const safe = program.pipe(\n      Effect.catchAll((error) => Effect.gen(function* () {\n        yield* Effect.logError(\"Error\", error)\n        return fallback\n      }))\n    )\n\n## Service — Context.Tag definition\n\n    import { Context, Effect } from \"effect\"\n\n    class Database extends Context.Tag(\"@app/Database\")<\n      Database,\n      {\n        readonly query: (sql: string) => Effect.Effect<unknown[]>\n        readonly execute: (sql: string) => Effect.Effect<void>\n      }\n    >() {}\n\n## Service — Layer implementation with dependencies\n\n    import { Context, Effect, Layer } from \"effect\"\n\n    class Users extends Context.Tag(\"@app/Users\")<\n      Users,\n      {\n        readonly findById: (id: UserId) => Effect.Effect<User, UserNotFoundError>\n      }\n    >() {\n      static readonly layer = Layer.effect(\n        Users,\n        Effect.gen(function* () {\n          const db = yield* Database\n          const analytics = yield* Analytics\n\n          const findById = Effect.fn(\"Users.findById\")(function* (id: UserId) {\n            yield* analytics.track(\"user.find\", { id })\n            const rows = yield* db.query(`SELECT * FROM users WHERE id = '${id}'`)\n            if (rows.length === 0) return yield* new UserNotFoundError({ id })\n            return User.make(rows[0] as any)\n          })\n\n          return Users.of({ findById })\n        })\n      )\n    }\n\n## Schema — Class with branded ID\n\n    import { Schema } from \"effect\"\n\n    const UserId = Schema.String.pipe(Schema.brand(\"UserId\"))\n    type UserId = typeof UserId.Type\n\n    class User extends Schema.Class<User>(\"User\")({\n      id: UserId,\n      name: Schema.String,\n      email: Schema.String,\n      createdAt: Schema.Date,\n    }) {\n      get displayName() { return `${this.name} (${this.email})` }\n    }\n\n## Schema — branded primitives\n\n    const Email = Schema.String.pipe(Schema.brand(\"Email\"))\n    type Email = typeof Email.Type\n\n    const Port = Schema.Int.pipe(Schema.between(1, 65535), Schema.brand(\"Port\"))\n    type Port = typeof Port.Type\n\n## Schema — tagged union + Match\n\n    import { Match, Schema } from \"effect\"\n\n    class Success extends Schema.TaggedClass<Success>()(\"Success\", { value: Schema.Number }) {}\n    class Failure extends Schema.TaggedClass<Failure>()(\"Failure\", { error: Schema.String }) {}\n\n    const Result = Schema.Union(Success, Failure)\n    type Result = typeof Result.Type\n\n    const render = (r: Result) =>\n      Match.valueTags(r, {\n        Success: ({ value }) => `Got: ${value}`,\n        Failure: ({ error }) => `Error: ${error}`,\n      })\n\n## Schema — JSON encode/decode\n\n    const MoveFromJson = Schema.parseJson(Move)\n\n    // decode from JSON string\n    const move = yield* Schema.decodeUnknown(MoveFromJson)(jsonString)\n\n    // encode to JSON string\n    const json = yield* Schema.encode(MoveFromJson)(move)\n\n## Config — service layer with redacted secrets\n\n    import { Config, Context, Effect, Layer, Redacted, Schema } from \"effect\"\n\n    const Port = Schema.NumberFromString.pipe(Schema.int(), Schema.between(1, 65535), Schema.brand(\"Port\"))\n    type Port = typeof Port.Type\n\n    class AppConfig extends Context.Tag(\"@app/AppConfig\")<\n      AppConfig,\n      {\n        readonly port: Port\n        readonly apiKey: Redacted.Redacted\n        readonly env: \"development\" | \"staging\" | \"production\"\n      }\n    >() {\n      static readonly layer = Layer.effect(\n        AppConfig,\n        Effect.gen(function* () {\n          const port   = yield* Schema.Config(\"PORT\", Port)\n          const apiKey = yield* Config.redacted(\"API_KEY\")\n          const env    = yield* Schema.Config(\"ENV\", Schema.Literal(\"development\", \"staging\", \"production\"))\n          return AppConfig.of({ port, apiKey, env })\n        })\n      )\n\n      static readonly testLayer = Layer.succeed(AppConfig, AppConfig.of({\n        port: Port.make(3000),\n        apiKey: Redacted.make(\"test-key\"),\n        env: \"development\",\n      }))\n    }\n\n## Resilience — retry, timeout, span\n\n    import { Effect, Schedule } from \"effect\"\n\n    const retryPolicy = Schedule.exponential(\"100 millis\").pipe(\n      Schedule.compose(Schedule.recurs(3))\n    )\n\n    const resilient = callExternalApi.pipe(\n      Effect.timeout(\"2 seconds\"),\n      Effect.retry(retryPolicy),\n      Effect.timeout(\"10 seconds\"),\n      Effect.tap((data) => Effect.logInfo(`Fetched: ${data}`)),\n      Effect.withSpan(\"callExternalApi\")\n    )\n\n## Testing — per-test layer (preferred)\n\n    import { expect, it } from \"@effect/vitest\"\n    import { Effect } from \"effect\"\n\n    it.effect(\"creates a user\", () =>\n      Effect.gen(function* () {\n        const users = yield* Users\n        const user = yield* users.findById(UserId.make(\"u-1\"))\n        expect(user.name).toBe(\"Alice\")\n      }).pipe(Effect.provide(Users.testLayer))\n    )\n\n## Testing — suite-shared layer\n\n    it.layer(Users.testLayer)(\"users suite\", (it) => {\n      it.effect(\"finds user\", () => Effect.gen(function* () {\n        const users = yield* Users\n        expect(yield* users.findById(UserId.make(\"u-1\"))).toBeDefined()\n      }))\n    })\n\n## Testing — in-memory test layer\n\n    static readonly testLayer = Layer.sync(Users, () => {\n      const store = new Map([[\"u-1\", User.make({ id: UserId.make(\"u-1\"), name: \"Alice\", email: \"a@example.com\", createdAt: new Date() })]])\n      return Users.of({\n        findById: (id) => Effect.succeed(store.get(id)!),\n      })\n    })\n\n## Layer composition — entry point\n\n    import { Layer, Effect } from \"effect\"\n\n    const dbLayer = Postgres.layer({ url: \"postgres://localhost/mydb\", poolSize: 10 })\n\n    const appLayer = UsersLayer.pipe(\n      Layer.provideMerge(dbLayer),\n      Layer.provideMerge(AnalyticsLayer),\n      Layer.provideMerge(ConfigLayer)\n    )\n\n    Effect.runPromise(program.pipe(Effect.provide(appLayer)))\n\n## Defect promotion — orDie at entry point\n\n    const main = Effect.gen(function* () {\n      const config = yield* loadConfig.pipe(Effect.orDie)\n      yield* startServer(config)\n    })\n",
    "anti-patterns": "WRONG: async function foo() { ... }\nRIGHT: const foo = Effect.fn(\"foo\")(function* () { ... })\n\nWRONG: try { ... } catch (e) { ... }\nRIGHT: Effect.catchTag / Effect.catchAll\n\nWRONG: throw new Error(\"not found\")\nRIGHT: yield* new UserNotFoundError({ id }) (Schema.TaggedError)\n\nWRONG: class MyError extends Error { ... }\nRIGHT: class MyError extends Schema.TaggedError<MyError>()(\"MyError\", { ... }) {}\n\nWRONG: Promise<T> as service method return type\nRIGHT: Effect.Effect<A, E> as service method return type\n\nWRONG: Calling Postgres.layer(...) in multiple places\nRIGHT: const dbLayer = Postgres.layer(...) — assign once, share reference\n\nWRONG: Scattered Effect.provide(...) throughout codebase\nRIGHT: Provide once at entry point via composed appLayer\n\nWRONG: Effect.provide inside service method implementations\nRIGHT: Layer composition handles all dependency wiring\n\nWRONG: Config.string(\"PORT\") for validated/branded values\nRIGHT: Schema.Config(\"PORT\", Port)\n\nWRONG: console.log(apiKey) or Config.string(\"SECRET\")\nRIGHT: Config.redacted(\"SECRET\") — logs as <redacted>\n\nWRONG: Raw string for domain IDs (userId: string)\nRIGHT: Schema.String.pipe(Schema.brand(\"UserId\"))\n\nWRONG: Plain generator function* for effectful code\nRIGHT: Effect.fn(\"name\")(function* (...) { ... }) for tracing + spans\n\nWRONG: Effect.gen without yield* (using .then or await)\nRIGHT: yield* inside Effect.gen(function* () { ... })\n\nWRONG: interface + manual tag for services\nRIGHT: class Db extends Context.Tag(\"@app/Db\")<Db, { ... }>() {}\n\nWRONG: Inline object literals for data models\nRIGHT: Schema.Class / Schema.TaggedClass for runtime-validated models\n\nWRONG: Union types via string literals or manual discriminants\nRIGHT: Schema.Union(VariantA, VariantB) + Match.valueTags\n\nWRONG: Mutable service interface properties\nRIGHT: readonly on all service interface properties\n\nWRONG: it(\"test\", async () => { ... }) with manual runPromise\nRIGHT: it.effect(\"test\", () => Effect.gen(function* () { ... }))\n\nWRONG: Writing full implementation before defining service contracts\nRIGHT: Sketch Context.Tag contracts first, implement layers after\n",
    "http-server": "# Effect-First TypeScript — HTTP Server (HttpApi)\n\nPackage: @effect/platform (HttpApi, HttpApiBuilder, HttpApiEndpoint, HttpApiGroup, HttpApiMiddleware, HttpApiSecurity)\n\n## Imports\n\n    import {\n      HttpApi, HttpApiBuilder, HttpApiEndpoint, HttpApiGroup,\n      HttpApiMiddleware, HttpApiSecurity\n    } from \"@effect/platform\"\n\n## Step 1 — Define endpoints\n\n    import { HttpApiEndpoint, HttpApiGroup, HttpApi } from \"@effect/platform\"\n    import { Schema } from \"effect\"\n\n    class User extends Schema.Class<User>(\"User\")({\n      id: Schema.String,\n      name: Schema.String,\n    }) {}\n\n    class UserNotFound extends Schema.TaggedError<UserNotFound>()(\"UserNotFound\", {\n      id: Schema.String,\n    }) {}\n\n    class UsersGroup extends HttpApiGroup.make(\"users\")\n      .add(\n        HttpApiEndpoint.get(\"findById\", \"/users/:id\")\n          .setPath(Schema.Struct({ id: Schema.String }))\n          .addSuccess(User)\n          .addError(UserNotFound, { status: 404 })\n      )\n      .add(\n        HttpApiEndpoint.post(\"create\", \"/users\")\n          .setPayload(Schema.Struct({ name: Schema.NonEmptyString }))\n          .addSuccess(User, { status: 201 })\n      )\n      .prefix(\"/api\") {}\n\n    class MyApi extends HttpApi.make(\"myApi\").add(UsersGroup) {}\n\n\n## Step 2 — Implement handlers\n\n    import { HttpApiBuilder } from \"@effect/platform\"\n    import { Effect, Layer } from \"effect\"\n\n    const UsersGroupLive = HttpApiBuilder.group(MyApi, \"users\", (handlers) =>\n      handlers\n        .handle(\"findById\", ({ path }) =>\n          Effect.gen(function* () {\n            const users = yield* Users\n            return yield* users.findById(path.id)\n          })\n        )\n        .handle(\"create\", ({ payload }) =>\n          Effect.gen(function* () {\n            const users = yield* Users\n            return yield* users.create(payload.name)\n          })\n        )\n    )\n\n\n## Step 3 — Serve\n\n    import { NodeHttpServer } from \"@effect/platform-node\"\n    import { HttpApiBuilder } from \"@effect/platform\"\n    import { Layer, Effect } from \"effect\"\n    import { createServer } from \"node:http\"\n\n    const ApiLive = HttpApiBuilder.api(MyApi).pipe(\n      Layer.provide(UsersGroupLive),\n      Layer.provide(Users.layer)\n    )\n\n    const ServerLive = NodeHttpServer.layer(createServer, { port: 3000 })\n\n    const app = HttpApiBuilder.serve().pipe(\n      Layer.provide(ServerLive),\n      Layer.provide(ApiLive)\n    )\n\n    Layer.launch(app).pipe(Effect.runPromise)\n\n\n## HttpApi key constructors\n\n    HttpApi.make(id)                                — create API\n    HttpApiGroup.make(id)                           — create group\n    HttpApiEndpoint.get(name, path)                 — GET endpoint\n    HttpApiEndpoint.post(name, path)                — POST endpoint\n    HttpApiEndpoint.put(name, path)                 — PUT endpoint\n    HttpApiEndpoint.del(name, path)                 — DELETE endpoint\n    HttpApiEndpoint.patch(name, path)               — PATCH endpoint\n\n## Endpoint schema methods (chainable)\n\n    .setPath(Schema.Struct({ id: Schema.String }))  — path params\n    .setPayload(schema)                              — request body (POST/PUT/PATCH)\n    .setUrlParams(schema)                            — query string params (GET)\n    .setHeaders(schema)                              — required headers\n    .addSuccess(schema, { status: 200 })             — success response\n    .addError(schema, { status: 404 })               — error response\n    .prefix(\"/v1\")                                   — path prefix\n\n## Group / API composition\n\n    group.add(endpoint)                              — add endpoint to group\n    group.addError(schema, { status })               — shared error for all endpoints\n    group.prefix(\"/api\")                             — prefix all routes\n    api.add(group)                                   — add group to api\n    api.addError(schema, { status })                 — global error\n\n## Builder\n\n    HttpApiBuilder.api(MyApi)                        — Layer<HttpApi.Api>\n    HttpApiBuilder.group(api, name, build)           — Layer for a group\n    HttpApiBuilder.serve()                           — Layer that starts server\n    HttpApiBuilder.toWebHandler(layer)               — { handler, dispose } for Cloudflare/Bun\n\n\n## Security\n\n    import { HttpApiSecurity, HttpApiMiddleware } from \"@effect/platform\"\n\n    class AuthMiddleware extends HttpApiMiddleware.Tag<AuthMiddleware>()(\"AuthMiddleware\", {\n      provides: CurrentUser,\n      security: { bearer: HttpApiSecurity.bearer },\n    }) {}\n\n    // Apply to group\n    class SecureGroup extends HttpApiGroup.make(\"secure\")\n      .middleware(AuthMiddleware)\n      .add(...) {}\n\n    // Implement middleware\n    const AuthMiddlewareLive = Layer.effect(AuthMiddleware, Effect.gen(function* () {\n      return AuthMiddleware.of({\n        bearer: (token) => Effect.gen(function* () {\n          // validate token, return CurrentUser\n        })\n      })\n    }))\n\n\n## Anti-patterns\n\nWRONG: Manual HttpRouter.get/post for typed APIs\nRIGHT: HttpApi + HttpApiEndpoint for schema-validated, auto-documented endpoints\n\nWRONG: Parsing request body manually in handlers\nRIGHT: .setPayload(schema) — decoded and validated before handler runs\n\nWRONG: Returning HttpServerResponse from handlers\nRIGHT: Return domain types; framework encodes via success/error schemas\n\nWRONG: Implementing auth checks inside each handler\nRIGHT: HttpApiMiddleware + HttpApiSecurity applied to group or api\n",
    "http-client": "# Effect-First TypeScript — HTTP Client\n\nPackage: @effect/platform (HttpClient, HttpClientRequest, HttpClientResponse, HttpClientError)\n\n## Imports\n\n    import { HttpClient, HttpClientRequest, HttpClientResponse, FetchHttpClient } from \"@effect/platform\"\n    import { NodeHttpClient } from \"@effect/platform-node\"\n    import { Effect, Schema } from \"effect\"\n\n## Basic GET\n\n    const fetchUser = Effect.fn(\"fetchUser\")(function* (id: string) {\n      const client = yield* HttpClient.HttpClient\n      const response = yield* client.get(`https://api.example.com/users/${id}`)\n      return yield* HttpClientResponse.schemaBodyJson(User)(response)\n    })\n\n    // Provide the client layer\n    fetchUser(\"u-1\").pipe(Effect.provide(FetchHttpClient.layer))\n\n## POST with JSON body\n\n    const createUser = Effect.fn(\"createUser\")(function* (name: string) {\n      const client = yield* HttpClient.HttpClient\n      const request = HttpClientRequest.post(\"https://api.example.com/users\").pipe(\n        HttpClientRequest.jsonBody({ name })\n      )\n      const response = yield* client.execute(request)\n      return yield* HttpClientResponse.schemaBodyJson(User)(response)\n    })\n\n## HttpApiClient — typed client from HttpApi definition\n\n    import { HttpApiClient } from \"@effect/platform\"\n\n    const program = Effect.gen(function* () {\n      const client = yield* HttpApiClient.make(MyApi, {\n        baseUrl: \"https://api.example.com\",\n      })\n      const user = yield* client.users.findById({ path: { id: \"u-1\" } })\n    })\n\n## Resilience — retry + timeout\n\n    const resilientFetch = fetchUser(\"u-1\").pipe(\n      Effect.retry(Schedule.exponential(\"200 millis\").pipe(Schedule.compose(Schedule.recurs(3)))),\n      Effect.timeout(\"10 seconds\"),\n      Effect.withSpan(\"fetchUser\")\n    )\n\n\n## Key types\n\n    HttpClient.HttpClient                — Context.Tag for the client service\n    HttpClientRequest.HttpClientRequest  — immutable request description\n    HttpClientResponse.HttpClientResponse — response with schema decoding\n    HttpClientError.HttpClientError      — typed error (RequestError | ResponseError)\n\n## Client methods\n\n    client.get(url, options?)            — GET request\n    client.post(url, options?)           — POST request\n    client.put(url, options?)            — PUT request\n    client.del(url, options?)            — DELETE request\n    client.patch(url, options?)          — PATCH request\n    client.head(url, options?)           — HEAD request\n    client.execute(request)              — execute arbitrary request\n\n## Response decoding\n\n    HttpClientResponse.schemaBodyJson(schema)(response)   — decode JSON body\n    HttpClientResponse.text(response)                     — body as string\n    HttpClientResponse.json(response)                     — body as unknown JSON\n    HttpClientResponse.stream(response)                   — body as Stream<Uint8Array>\n\n## Layers\n\n    FetchHttpClient.layer                — uses globalThis.fetch (browser, Cloudflare Workers, Bun)\n    NodeHttpClient.layer                 — uses Node.js undici\n\n## Anti-patterns\n\nWRONG: fetch(url).then(r => r.json())\nRIGHT: client.get(url) |> HttpClientResponse.schemaBodyJson(Schema)\n\nWRONG: Manual error handling for HTTP status codes\nRIGHT: HttpClient errors are typed; use Effect.catchTag(\"ResponseError\", ...)\n\nWRONG: Hardcoding fetch in service implementations\nRIGHT: Depend on HttpClient.HttpClient tag; provide FetchHttpClient.layer or NodeHttpClient.layer\n\nWRONG: Building typed API clients by hand\nRIGHT: HttpApiClient.make(MyApi) generates fully typed client from HttpApi definition\n",
    "sql": "# Effect-First TypeScript — SQL (@effect/sql)\n\n@effect/sql provides a tagged template literal SQL client, schema-validated queries, batched resolvers, and a Model system for domain objects with insert/update/json variants.\n\nPackage: @effect/sql (SqlClient, SqlSchema, SqlResolver, Model, Migrator)\nDB adapters: @effect/sql-pg, @effect/sql-sqlite-node, @effect/sql-mysql2, @effect/sql-mssql\n\n\n## Imports\n\n    import { SqlClient, SqlSchema, SqlResolver, Model } from \"@effect/sql\"\n    import { PgClient } from \"@effect/sql-pg\"        // or SqliteClient, etc.\n    import { Effect, Schema } from \"effect\"\n\n\n## SqlClient — tagged template queries\n\n    const program = Effect.gen(function* () {\n      const sql = yield* SqlClient.SqlClient\n\n      // select — returns ReadonlyArray<unknown>\n      const rows = yield* sql`SELECT * FROM users WHERE id = ${userId}`\n\n      // insert\n      yield* sql`INSERT INTO users ${sql.insert({ id, name, email })}`\n\n      // update\n      yield* sql`UPDATE users SET ${sql.update({ name, email })} WHERE id = ${id}`\n\n      // transactions\n      yield* sql.withTransaction(\n        Effect.gen(function* () {\n          yield* sql`INSERT INTO orders ${sql.insert(order)}`\n          yield* sql`UPDATE inventory SET qty = qty - 1 WHERE id = ${itemId}`\n        })\n      )\n    })\n\n\n## SqlSchema — validated queries\n\n    import { SqlClient, SqlSchema } from \"@effect/sql\"\n    import { Effect, Schema } from \"effect\"\n\n    const findUserById = SqlSchema.findOne({\n      Request: Schema.String,\n      Result: User,\n      execute: (id) => Effect.gen(function* () {\n        const sql = yield* SqlClient.SqlClient\n        return yield* sql`SELECT * FROM users WHERE id = ${id}`\n      }),\n    })\n\n    // SqlSchema variants:\n    // SqlSchema.findAll    — returns ReadonlyArray<A>\n    // SqlSchema.findOne    — returns Option<A>\n    // SqlSchema.single     — returns A (throws NoSuchElementException if missing)\n    // SqlSchema.void       — discards result\n\n\n## Model — domain objects with variants\n\n    import { Model } from \"@effect/sql\"\n    import { Schema } from \"effect\"\n\n    const GroupId = Schema.Number.pipe(Schema.brand(\"GroupId\"))\n\n    class Group extends Model.Class<Group>(\"Group\")({\n      id: Model.Generated(GroupId),\n      name: Schema.NonEmptyTrimmedString,\n      createdAt: Model.DateTimeInsertFromDate,\n      updatedAt: Model.DateTimeUpdateFromDate,\n    }) {}\n\n    // Variants auto-generated:\n    // Group            — select schema (all fields)\n    // Group.insert     — insert schema (id omitted, createdAt auto)\n    // Group.update     — update schema (all optional, updatedAt auto)\n    // Group.json       — JSON API schema\n    // Group.jsonCreate — JSON create schema\n    // Group.jsonUpdate — JSON update schema\n\n    // Model field helpers:\n    // Model.Generated(schema)              — omit from insert\n    // Model.GeneratedByApp(schema)         — required in insert, not from DB\n    // Model.DateTimeInsertFromDate         — auto DateTime on insert\n    // Model.DateTimeUpdateFromDate         — auto DateTime on update\n    // Model.Sensitive(schema)              — omit from json variants\n    // Model.FieldOption(schema)            — Option<A> field\n    // Model.JsonFromString(schema)         — JSON stored as string column\n\n\n## SqlResolver — batched queries with Effect Request\n\n    const UserById = SqlResolver.findById(\"UserById\", {\n      Id: UserId,\n      Result: User,\n      ResultId: (user) => user.id,\n      execute: (ids) => Effect.gen(function* () {\n        const sql = yield* SqlClient.SqlClient\n        return yield* sql`SELECT * FROM users WHERE id IN ${sql.in(ids)}`\n      }),\n    })\n\n    // Use:\n    const user = yield* UserById.execute(userId)\n\n    // SqlResolver variants:\n    // SqlResolver.findById   — returns Option<A>, keyed by ID\n    // SqlResolver.ordered    — results match request order 1:1\n    // SqlResolver.grouped    — group results by key (1:many)\n    // SqlResolver.void       — batched writes, no result\n\n\n## Model.makeRepository — CRUD from Model\n\n    const GroupRepo = Model.makeRepository(Group, {\n      tableName: \"groups\",\n      spanPrefix: \"GroupRepo\",\n      idColumn: \"id\",\n    })\n\n    // Provides: findById, insert, update, delete, etc.\n\n\n## Layers (provide at entry point)\n\n    // PostgreSQL\n    import { PgClient } from \"@effect/sql-pg\"\n    const DbLive = PgClient.layer({ url: \"postgres://localhost/mydb\" })\n\n    // SQLite\n    import { SqliteClient } from \"@effect/sql-sqlite-node\"\n    const DbLive = SqliteClient.layer({ filename: \"./data.db\" })\n\n    // Always assign to a const — memoization by reference\n    Effect.runPromise(program.pipe(Effect.provide(DbLive)))\n\n\n## Anti-patterns\n\nWRONG: String concatenation for SQL queries\nRIGHT: Tagged template: sql`SELECT * FROM users WHERE id = ${id}` (auto-parameterized)\n\nWRONG: Manual row-to-object mapping\nRIGHT: SqlSchema.findAll/findOne with Schema for validated decoding\n\nWRONG: N+1 queries in loops\nRIGHT: SqlResolver.findById / SqlResolver.grouped for automatic batching\n\nWRONG: Separate type definitions for insert vs select\nRIGHT: Model.Class generates all variants (select, insert, update, json) from one definition\n\nWRONG: Manual transaction begin/commit/rollback\nRIGHT: sql.withTransaction(effect) handles commit/rollback automatically\n",
    "cli": "# Effect-First TypeScript — CLI & Commands\n\nEffect provides two distinct capabilities:\n1. Command execution — run external processes via @effect/platform Command\n2. CLI argument parsing — use effect Config + Schema.Config for argv/env, or @effect/cli for full CLI apps\n\n\n## Imports\n\n    import { Command, CommandExecutor } from \"@effect/platform\"\n    import { NodeCommandExecutor, NodeFileSystem } from \"@effect/platform-node\"\n    import { Effect, Stream } from \"effect\"\n\n\n## Running external commands\n\n    const listFiles = Effect.gen(function* () {\n      // Simple: get stdout as string\n      const output = yield* Command.make(\"ls\", \"-la\").pipe(Command.string)\n\n      // With options\n      const result = yield* Command.make(\"git\", \"status\")\n        .pipe(\n          Command.workingDirectory(\"/path/to/repo\"),\n          Command.env({ GIT_AUTHOR_NAME: \"bot\" }),\n          Command.string\n        )\n\n      // Exit code only\n      const code = yield* Command.make(\"npm\", \"test\").pipe(Command.exitCode)\n\n      return output\n    })\n\n    // Provide the executor\n    listFiles.pipe(\n      Effect.provide(NodeCommandExecutor.layer),\n      Effect.provide(NodeFileSystem.layer)\n    )\n\n\n## Streaming output\n\n    // Stream stdout line by line\n    const logStream = Command.make(\"tail\", \"-f\", \"/var/log/app.log\").pipe(\n      Command.streamLines\n    )\n\n    // Process as a stream\n    const program = logStream.pipe(\n      Stream.filter((line) => line.includes(\"ERROR\")),\n      Stream.tap((line) => Effect.logError(line)),\n      Stream.runDrain\n    )\n\n    // Raw byte stream\n    const bytes = Command.make(\"cat\", \"file.bin\").pipe(Command.stream)\n\n\n## Piping commands\n\n    const pipeline = Command.make(\"cat\", \"data.csv\").pipe(\n      Command.pipeTo(Command.make(\"grep\", \"error\")),\n      Command.pipeTo(Command.make(\"wc\", \"-l\")),\n      Command.string\n    )\n\n\n## Process with stdin\n\n    const withInput = Command.make(\"wc\", \"-w\").pipe(\n      Command.feed(\"hello world this is a test\"),\n      Command.string\n    )\n\n\n## Command API reference\n\n    Command.make(cmd, ...args)           — create command\n    Command.string(cmd)                  — run, return stdout as string\n    Command.lines(cmd)                   — run, return stdout as string[]\n    Command.exitCode(cmd)                — run, return exit code\n    Command.stream(cmd)                  — stdout as Stream<Uint8Array>\n    Command.streamLines(cmd)             — stdout as Stream<string>\n    Command.start(cmd)                   — start Process (stdin/stdout/stderr access)\n    Command.pipeTo(target)               — pipe stdout to another command\n    Command.feed(input)                  — feed string to stdin\n    Command.workingDirectory(path)       — set cwd\n    Command.env(record)                  — set env vars\n    Command.runInShell(shell)            — run via shell (boolean | string)\n\n## Layers\n\n    NodeCommandExecutor.layer            — Node.js process execution\n    NodeFileSystem.layer                 — required by NodeCommandExecutor\n\n\n## CLI argument parsing with Config\n\nFor simple CLIs, use effect’s Config module (reads from env + argv):\n\n    import { Config, Effect, Schema } from \"effect\"\n\n    const program = Effect.gen(function* () {\n      const port = yield* Schema.Config(\"PORT\", Schema.NumberFromString.pipe(\n        Schema.int(), Schema.between(1, 65535)\n      ))\n      const verbose = yield* Config.withDefault(Config.boolean(\"VERBOSE\"), false)\n      const dbUrl = yield* Config.redacted(\"DATABASE_URL\")\n      yield* Effect.logInfo(`Starting on port ${port}`)\n    })\n\n\n## Anti-patterns\n\nWRONG: child_process.exec(cmd, callback)\nRIGHT: Command.make(cmd).pipe(Command.string)\n\nWRONG: Manually parsing stdout string into lines\nRIGHT: Command.streamLines(cmd) returns Stream<string>\n\nWRONG: process.env.PORT with manual parseInt\nRIGHT: Schema.Config(\"PORT\", Schema.NumberFromString) with validation\n\nWRONG: Forgetting to provide CommandExecutor layer\nRIGHT: Effect.provide(NodeCommandExecutor.layer) + Effect.provide(NodeFileSystem.layer)\n",
    "streams": "# Effect-First TypeScript — Streams\n\nStream<A, E, R> is a pull-based, backpressured sequence of values.\n\nPackage: effect (Stream, Sink, Channel)\n\n## Imports\n\n    import { Stream, Sink, Chunk, Effect, Schedule } from \"effect\"\n\n## Creating streams\n\n    // From values\n    Stream.make(1, 2, 3)\n    Stream.fromIterable([1, 2, 3])\n    Stream.range(1, 100)\n    Stream.empty\n\n    // From Effect (single value stream)\n    Stream.fromEffect(fetchUser(id))\n\n    // Repeated effect\n    Stream.repeatEffect(readSensor)\n    Stream.repeatEffectWithSchedule(pollApi, Schedule.spaced(\"5 seconds\"))\n\n    // Pagination\n    Stream.paginate(initialCursor, (cursor) => {\n      const page = fetchPage(cursor)\n      return [page.items, Option.fromNullable(page.nextCursor)]\n    })\n\n    // From async\n    Stream.fromAsyncIterable(asyncIter, (e) => new MyError({ cause: e }))\n    Stream.async((emit) => { /* push values via emit */ })\n\n    // Infinite\n    Stream.iterate(0, (n) => n + 1)\n    Stream.repeatValue(\"tick\")\n\n\n## Transforming streams\n\n    stream.pipe(\n      Stream.map((x) => x * 2),\n      Stream.filter((x) => x > 10),\n      Stream.take(5),\n      Stream.drop(2),\n      Stream.flatMap((x) => Stream.make(x, x + 1)),\n      Stream.mapEffect((x) => processItem(x)),\n      Stream.tap((x) => Effect.logInfo(`Processing: ${x}`)),\n      Stream.scan(0, (acc, x) => acc + x),\n    )\n\n    // Chunked operations (batch-efficient)\n    stream.pipe(\n      Stream.mapChunks((chunk) => Chunk.map(chunk, transform)),\n      Stream.grouped(100),           // group into chunks of 100\n      Stream.debounce(\"500 millis\"), // debounce emissions\n    )\n\n\n## Consuming streams\n\n    // Collect all (careful with large streams)\n    const items = yield* Stream.runCollect(stream)  // Chunk<A>\n\n    // Fold\n    const sum = yield* Stream.runFold(stream, 0, (acc, x) => acc + x)\n\n    // ForEach (side effects)\n    yield* Stream.runForEach(stream, (item) => processItem(item))\n\n    // Drain (discard values, run for effects)\n    yield* Stream.runDrain(stream)\n\n    // Count\n    const n = yield* Stream.runCount(stream)\n\n    // With Sink\n    yield* Stream.run(stream, Sink.collectAll())\n    yield* Stream.run(stream, Sink.foldLeft(0, (acc, x) => acc + x))\n\n\n## Combining streams\n\n    // Merge (interleave, concurrent)\n    Stream.merge(streamA, streamB)\n    Stream.mergeAll([streamA, streamB, streamC], { concurrency: 3 })\n\n    // Concat (sequential)\n    Stream.concat(streamA, streamB)\n\n    // Zip (pair elements)\n    Stream.zip(streamA, streamB)          // Stream<[A, B]>\n    Stream.zipWith(streamA, streamB, (a, b) => a + b)\n\n\n## Error handling\n\n    stream.pipe(\n      Stream.catchAll((e) => Stream.make(fallbackValue)),\n      Stream.catchTag(\"NetworkError\", (e) => Stream.empty),\n      Stream.retry(Schedule.exponential(\"1 second\")),\n    )\n\n\n## Sinks (stream consumers)\n\n    Sink.collectAll()                    — collect into Chunk<A>\n    Sink.foldLeft(init, f)               — fold without early termination\n    Sink.fold(init, contFn, f)           — fold with early termination\n    Sink.forEach(f)                      — side-effect per element\n    Sink.head                            — first element as Option<A>\n    Sink.last                            — last element as Option<A>\n    Sink.count                           — count elements\n    Sink.sum                             — sum numbers\n    Sink.take(n)                         — take first n into Chunk<A>\n\n\n## Common patterns\n\n    // Polling with schedule\n    const poller = Stream.repeatEffectWithSchedule(\n      checkStatus,\n      Schedule.spaced(\"10 seconds\")\n    ).pipe(\n      Stream.takeUntil((status) => status === \"complete\")\n    )\n\n    // Batched processing\n    const batchProcessor = eventStream.pipe(\n      Stream.grouped(50),\n      Stream.mapEffect((batch) => processBatch(Chunk.toReadonlyArray(batch)),\n        { concurrency: 3 }\n      ),\n      Stream.runDrain\n    )\n\n\n## Anti-patterns\n\nWRONG: Collecting unbounded stream into array\nRIGHT: Stream.runForEach or Stream.runFold for bounded consumption\n\nWRONG: for await (const x of asyncIter) with manual error handling\nRIGHT: Stream.fromAsyncIterable + Stream.mapEffect for typed errors\n\nWRONG: setInterval + mutable array for polling\nRIGHT: Stream.repeatEffectWithSchedule + Stream.takeUntil\n\nWRONG: Manual batching with counters\nRIGHT: Stream.grouped(n) + Stream.mapEffect with concurrency\n\nWRONG: Promise.all for concurrent stream processing\nRIGHT: Stream.mergeAll with concurrency option\n",
    "concurrency": "# Effect-First TypeScript — Concurrency\n\n## Imports\n\n    import { Effect, Fiber, FiberSet, FiberMap } from \"effect\"\n\n## Structured concurrency\n\n    // Run in parallel (all succeed or first error)\n    const result = yield* Effect.all([taskA, taskB, taskC], { concurrency: 2 })\n\n    // ForEach with concurrency + batching\n    yield* Effect.forEach(items, (item) => process(item), { concurrency: 5 })\n\n## Fork / join\n\n    const fiber = yield* Effect.fork(task)\n    const value = yield* Fiber.join(fiber)\n\n    // Fork and interrupt\n    const fiber = yield* Effect.fork(longRunning)\n    yield* Fiber.interrupt(fiber)\n\n    // Scoped fork (auto-interrupt on scope close)\n    const fiber = yield* Effect.forkScoped(task)\n    yield* Fiber.join(fiber)\n\n## Race\n\n    const fastest = yield* Effect.race(taskA, taskB)\n    const winner = yield* Effect.raceAll([taskA, taskB, taskC])\n\n## Fiber collections\n\n    const set = yield* FiberSet.make()\n    yield* FiberSet.run(set, taskA)\n    yield* FiberSet.run(set, taskB)\n    yield* FiberSet.join(set)\n\n    const map = yield* FiberMap.make()\n    yield* FiberMap.run(map, \"job-1\", taskA)\n    yield* FiberMap.run(map, \"job-2\", taskB)\n    yield* FiberMap.join(map, \"job-1\")\n\n## Interrupt\n\n    const fiber = yield* Effect.fork(task)\n    yield* Fiber.interrupt(fiber)\n    yield* Fiber.await(fiber)  // observe exit\n",
    "resources": "# Effect-First TypeScript — Resources & Scope\n\n## Imports\n\n    import { Effect, Layer, Scope, Pool, ScopedRef } from \"effect\"\n\n## acquireRelease\n\n    const file = yield* Effect.acquireRelease(\n      openFile(path),\n      (handle) => closeFile(handle)\n    )\n\n    const program = Effect.acquireUseRelease(\n      connectDb,\n      (db) => db.query(\"select * from users\"),\n      (db) => db.close\n    )\n\n## addFinalizer\n\n    const program = Effect.gen(function* () {\n      yield* Effect.addFinalizer(() => Effect.logInfo(\"cleanup\"))\n      return yield* doWork\n    })\n\n## Scope service\n\n    const scoped = Effect.scoped(\n      Effect.gen(function* () {\n        const scope = yield* Scope.Scope\n        return scope\n      })\n    )\n\n## Layer.scoped\n\n    class Connection extends Context.Tag(\"@app/Connection\")<\n      Connection,\n      { readonly query: (sql: string) => Effect.Effect<unknown[]> }\n    >() {}\n\n    const ConnectionLive = Layer.scoped(\n      Connection,\n      Effect.acquireRelease(connectDb, (db) => db.close)\n    )\n\n## Pools\n\n    const pool = yield* Pool.make({\n      acquire: connectDb,\n      size: 10,\n      timeToLive: \"10 minutes\",\n      concurrency: 2,\n    })\n\n    const db = yield* Pool.get(pool)\n\n## ScopedRef\n\n    const ref = yield* ScopedRef.fromAcquire(connectDb)\n    const db = yield* ScopedRef.get(ref)\n",
    "full": "# Effect-First TypeScript — Rules\n\n## RULE 1 — Effect.fn for all named effectful functions\n- Wrap every named effectful function (including nullary) with Effect.fn(\"name\")(function* (...) { ... })\n- Optional second arg transforms the whole effect (retry, timeout, etc.)\n- Never use async functions for effectful code\n\n## RULE 2 — Effect.gen for sequencing\n- Use Effect.gen(function* () { ... }) to sequence effects\n- yield* each Effect; return final value\n\n## RULE 3 — Schema.TaggedError for all errors\n- Every error: class MyError extends Schema.TaggedError<MyError>()(\"MyError\", { ...fields })\n- Recover with Effect.catchTag(\"Tag\", handler) or Effect.catchAll\n- E channel = domain failures callers handle (not found, validation, rate limit)\n- Defects (Effect.die / Effect.orDie) = bugs/invariant violations, handled at boundary only\n\n## RULE 4 — Context.Tag + Layer for all services\n- class Svc extends Context.Tag(\"@scope/Svc\")<Svc, { readonly method: (...) => Effect.Effect<A, E> }>() {}\n- Tag IDs globally unique (@scope/Name)\n- Service methods must have R = never; dependencies resolved via Layer, not method signatures\n- Implement via static layer = Layer.effect(Tag, Effect.gen(function* () { ... }))\n- Layer names: layer, testLayer, postgresLayer (camelCase + Layer suffix)\n- Compose layers at entry point with Layer.provideMerge; provide once via Effect.provide(appLayer)\n- Parameterized layer constructors: assign to module-level const before reuse (memoization by reference)\n\n## RULE 5 — Schema for all data\n- Schema.Class for records: class User extends Schema.Class<User>(\"User\")({ ...fields }) {}\n- Schema.TaggedClass for union variants, discriminate with Match.valueTags\n- Brand all domain primitives: Schema.String.pipe(Schema.brand(\"UserId\"))\n- Type extraction: type UserId = typeof UserId.Type\n- JSON: Schema.parseJson(MySchema) for encode/decode\n\n## RULE 6 — Schema.Config + config service layers\n- Schema.Config(\"ENV_VAR\", MySchema) for validated/branded config\n- Config.redacted(\"SECRET\") for secrets (auto-hidden in logs)\n- Group related config into a single Context.Tag service with layer + testLayer\n\n## RULE 7 — Resilience via pipe\n- Chain: Effect.timeout, Effect.retry(Schedule.exponential(...).pipe(Schedule.compose(Schedule.recurs(n)))), Effect.tap, Effect.withSpan\n- Apply as .pipe() instrumentation on effects\n\n## RULE 8 — @effect/vitest for testing\n- it.effect(\"name\", () => Effect.gen(function* () { ... }).pipe(Effect.provide(Svc.testLayer)))\n- it.layer(Svc.testLayer)(\"suite\", (it) => { it.effect(...) }) for shared expensive resources\n- Test layers: Layer.sync(Tag, () => Tag.of({ ...in-memory impl }))\n\n## RULE 9 — Service-driven development workflow\n1. Sketch leaf service Tags (contracts, no impl)\n2. Write orchestration (higher-level services yield* leaf tags — compiles immediately)\n3. Implement leaf Layers\n4. Wire at entry point (compose into appLayer, provide once)\n\n## TypeScript Config (non-negotiable)\n- target: ES2022, module: NodeNext, moduleDetection: force\n- verbatimModuleSyntax: true, rewriteRelativeImportExtensions: true\n- strict: true, exactOptionalPropertyTypes: true\n- noUnusedLocals: true, noImplicitOverride: true\n- declarationMap: true, sourceMap: true, skipLibCheck: true\n\n\n# Effect-TS Quick Reference\n\n## Imports\nimport { Effect, Layer, Context, Schema, Config, Schedule, Match, Redacted } from \"effect\"\nimport { HttpClient, HttpClientResponse } from \"@effect/platform\"\nimport { it, expect } from \"@effect/vitest\"\n\n## Type Signatures\nEffect<A, E, R>  A=success  E=typed-error  R=required-services\nSchema.Class<T>(\"Tag\")({ field: Schema.String })  — branded record\nSchema.TaggedError<T>()(\"Tag\", { field: Schema.X })  — typed error\nSchema.TaggedClass<T>()(\"Tag\", { field: Schema.X })  — tagged variant\nContext.Tag(\"@scope/Name\")<Tag, Interface>()  — service tag\nLayer.effect(Tag, Effect.gen(...))  — service impl\nLayer.sync(Tag, () => Tag.of({...}))  — sync/test impl\nLayer.succeed(Tag, Tag.of({...}))  — constant impl\n\n## Effect Primitives\nEffect.succeed(value)             pure value\nEffect.fail(error)                typed error (E channel)\nEffect.sync(() => expr)           wrap sync side-effect\nEffect.promise(() => fetch(...))  wrap Promise\nEffect.die(defect)                unrecoverable defect\nEffect.orDie                      promote E to defect\nEffect.logInfo(msg)               structured log\nEffect.logError(msg, cause)       error log\nEffect.runPromise(effect)         run at entry (async)\nEffect.runSync(effect)            run at entry (sync)\n\n## Generators\nEffect.gen(function* () { const x = yield* someEffect; return x })\nEffect.fn(\"name\")(function* (arg: T) { ... })  — named + traced\nEffect.fn(\"name\")(function* (...) { ... }, flow(Effect.retry(...), Effect.timeout(...)))  — with transform\n\n## .pipe() Combinators\nEffect.timeout(\"2 seconds\")\nEffect.retry(Schedule.exponential(\"100 millis\").pipe(Schedule.compose(Schedule.recurs(3))))\nEffect.tap((a) => Effect.logInfo(...))\nEffect.withSpan(\"spanName\")\nEffect.annotateCurrentSpan(\"key\", value)\nEffect.catchTag(\"ErrorTag\", (e) => fallback)\nEffect.catchAll((e) => fallback)\nEffect.provide(layer)\nEffect.orDie\n\n## Schema\nconst UserId = Schema.String.pipe(Schema.brand(\"UserId\"))\ntype UserId = typeof UserId.Type\nSchema.Config(\"ENV_VAR\", MySchema)  — validated config\nConfig.redacted(\"SECRET\")  — secrets (logs as <redacted>)\nSchema.parseJson(MySchema)  — JSON codec\nSchema.decodeUnknown(schema)(input)  — decode\nSchema.encode(schema)(value)  — encode\n\n## tsconfig compilerOptions (required)\ntarget: ES2022, module: NodeNext, moduleDetection: force,\nverbatimModuleSyntax: true, rewriteRelativeImportExtensions: true,\nstrict: true, exactOptionalPropertyTypes: true,\nnoUnusedLocals: true, noImplicitOverride: true,\ndeclarationMap: true, sourceMap: true, skipLibCheck: true\n\n\n# Effect-First TypeScript — Code Examples\n\n## Effect.fn — basic\n\n    import { Effect } from \"effect\"\n\n    const processUser = Effect.fn(\"processUser\")(function* (userId: string) {\n      const user = yield* getUser(userId)\n      return yield* processData(user)\n    })\n\n## Effect.fn — with retry transform\n\n    import { Effect, Schedule, flow } from \"effect\"\n\n    const fetchWithRetry = Effect.fn(\"fetchWithRetry\")(\n      function* (url: string) {\n        return yield* fetchData(url)\n      },\n      flow(\n        Effect.retry(Schedule.exponential(\"100 millis\").pipe(Schedule.compose(Schedule.recurs(3)))),\n        Effect.timeout(\"5 seconds\")\n      )\n    )\n\n## Effect.gen — sequencing\n\n    import { Effect } from \"effect\"\n\n    const program = Effect.gen(function* () {\n      const data = yield* fetchData\n      yield* Effect.logInfo(`Processing: ${data}`)\n      return yield* processData(data)\n    })\n\n## TaggedError — definition\n\n    import { Schema } from \"effect\"\n\n    class UserNotFoundError extends Schema.TaggedError<UserNotFoundError>()(\n      \"UserNotFoundError\",\n      { id: Schema.String }\n    ) {}\n\n    class RateLimitError extends Schema.TaggedError<RateLimitError>()(\n      \"RateLimitError\",\n      { retryAfter: Schema.Number }\n    ) {}\n\n## TaggedError — recovery\n\n    const result = program.pipe(\n      Effect.catchTag(\"UserNotFoundError\", (e) => Effect.succeed(defaultUser)),\n      Effect.catchTag(\"RateLimitError\", (e) => Effect.fail(new FatalError({ cause: e })))\n    )\n\n    const safe = program.pipe(\n      Effect.catchAll((error) => Effect.gen(function* () {\n        yield* Effect.logError(\"Error\", error)\n        return fallback\n      }))\n    )\n\n## Service — Context.Tag definition\n\n    import { Context, Effect } from \"effect\"\n\n    class Database extends Context.Tag(\"@app/Database\")<\n      Database,\n      {\n        readonly query: (sql: string) => Effect.Effect<unknown[]>\n        readonly execute: (sql: string) => Effect.Effect<void>\n      }\n    >() {}\n\n## Service — Layer implementation with dependencies\n\n    import { Context, Effect, Layer } from \"effect\"\n\n    class Users extends Context.Tag(\"@app/Users\")<\n      Users,\n      {\n        readonly findById: (id: UserId) => Effect.Effect<User, UserNotFoundError>\n      }\n    >() {\n      static readonly layer = Layer.effect(\n        Users,\n        Effect.gen(function* () {\n          const db = yield* Database\n          const analytics = yield* Analytics\n\n          const findById = Effect.fn(\"Users.findById\")(function* (id: UserId) {\n            yield* analytics.track(\"user.find\", { id })\n            const rows = yield* db.query(`SELECT * FROM users WHERE id = '${id}'`)\n            if (rows.length === 0) return yield* new UserNotFoundError({ id })\n            return User.make(rows[0] as any)\n          })\n\n          return Users.of({ findById })\n        })\n      )\n    }\n\n## Schema — Class with branded ID\n\n    import { Schema } from \"effect\"\n\n    const UserId = Schema.String.pipe(Schema.brand(\"UserId\"))\n    type UserId = typeof UserId.Type\n\n    class User extends Schema.Class<User>(\"User\")({\n      id: UserId,\n      name: Schema.String,\n      email: Schema.String,\n      createdAt: Schema.Date,\n    }) {\n      get displayName() { return `${this.name} (${this.email})` }\n    }\n\n## Schema — branded primitives\n\n    const Email = Schema.String.pipe(Schema.brand(\"Email\"))\n    type Email = typeof Email.Type\n\n    const Port = Schema.Int.pipe(Schema.between(1, 65535), Schema.brand(\"Port\"))\n    type Port = typeof Port.Type\n\n## Schema — tagged union + Match\n\n    import { Match, Schema } from \"effect\"\n\n    class Success extends Schema.TaggedClass<Success>()(\"Success\", { value: Schema.Number }) {}\n    class Failure extends Schema.TaggedClass<Failure>()(\"Failure\", { error: Schema.String }) {}\n\n    const Result = Schema.Union(Success, Failure)\n    type Result = typeof Result.Type\n\n    const render = (r: Result) =>\n      Match.valueTags(r, {\n        Success: ({ value }) => `Got: ${value}`,\n        Failure: ({ error }) => `Error: ${error}`,\n      })\n\n## Schema — JSON encode/decode\n\n    const MoveFromJson = Schema.parseJson(Move)\n\n    // decode from JSON string\n    const move = yield* Schema.decodeUnknown(MoveFromJson)(jsonString)\n\n    // encode to JSON string\n    const json = yield* Schema.encode(MoveFromJson)(move)\n\n## Config — service layer with redacted secrets\n\n    import { Config, Context, Effect, Layer, Redacted, Schema } from \"effect\"\n\n    const Port = Schema.NumberFromString.pipe(Schema.int(), Schema.between(1, 65535), Schema.brand(\"Port\"))\n    type Port = typeof Port.Type\n\n    class AppConfig extends Context.Tag(\"@app/AppConfig\")<\n      AppConfig,\n      {\n        readonly port: Port\n        readonly apiKey: Redacted.Redacted\n        readonly env: \"development\" | \"staging\" | \"production\"\n      }\n    >() {\n      static readonly layer = Layer.effect(\n        AppConfig,\n        Effect.gen(function* () {\n          const port   = yield* Schema.Config(\"PORT\", Port)\n          const apiKey = yield* Config.redacted(\"API_KEY\")\n          const env    = yield* Schema.Config(\"ENV\", Schema.Literal(\"development\", \"staging\", \"production\"))\n          return AppConfig.of({ port, apiKey, env })\n        })\n      )\n\n      static readonly testLayer = Layer.succeed(AppConfig, AppConfig.of({\n        port: Port.make(3000),\n        apiKey: Redacted.make(\"test-key\"),\n        env: \"development\",\n      }))\n    }\n\n## Resilience — retry, timeout, span\n\n    import { Effect, Schedule } from \"effect\"\n\n    const retryPolicy = Schedule.exponential(\"100 millis\").pipe(\n      Schedule.compose(Schedule.recurs(3))\n    )\n\n    const resilient = callExternalApi.pipe(\n      Effect.timeout(\"2 seconds\"),\n      Effect.retry(retryPolicy),\n      Effect.timeout(\"10 seconds\"),\n      Effect.tap((data) => Effect.logInfo(`Fetched: ${data}`)),\n      Effect.withSpan(\"callExternalApi\")\n    )\n\n## Testing — per-test layer (preferred)\n\n    import { expect, it } from \"@effect/vitest\"\n    import { Effect } from \"effect\"\n\n    it.effect(\"creates a user\", () =>\n      Effect.gen(function* () {\n        const users = yield* Users\n        const user = yield* users.findById(UserId.make(\"u-1\"))\n        expect(user.name).toBe(\"Alice\")\n      }).pipe(Effect.provide(Users.testLayer))\n    )\n\n## Testing — suite-shared layer\n\n    it.layer(Users.testLayer)(\"users suite\", (it) => {\n      it.effect(\"finds user\", () => Effect.gen(function* () {\n        const users = yield* Users\n        expect(yield* users.findById(UserId.make(\"u-1\"))).toBeDefined()\n      }))\n    })\n\n## Testing — in-memory test layer\n\n    static readonly testLayer = Layer.sync(Users, () => {\n      const store = new Map([[\"u-1\", User.make({ id: UserId.make(\"u-1\"), name: \"Alice\", email: \"a@example.com\", createdAt: new Date() })]])\n      return Users.of({\n        findById: (id) => Effect.succeed(store.get(id)!),\n      })\n    })\n\n## Layer composition — entry point\n\n    import { Layer, Effect } from \"effect\"\n\n    const dbLayer = Postgres.layer({ url: \"postgres://localhost/mydb\", poolSize: 10 })\n\n    const appLayer = UsersLayer.pipe(\n      Layer.provideMerge(dbLayer),\n      Layer.provideMerge(AnalyticsLayer),\n      Layer.provideMerge(ConfigLayer)\n    )\n\n    Effect.runPromise(program.pipe(Effect.provide(appLayer)))\n\n## Defect promotion — orDie at entry point\n\n    const main = Effect.gen(function* () {\n      const config = yield* loadConfig.pipe(Effect.orDie)\n      yield* startServer(config)\n    })\n\n\nWRONG: async function foo() { ... }\nRIGHT: const foo = Effect.fn(\"foo\")(function* () { ... })\n\nWRONG: try { ... } catch (e) { ... }\nRIGHT: Effect.catchTag / Effect.catchAll\n\nWRONG: throw new Error(\"not found\")\nRIGHT: yield* new UserNotFoundError({ id }) (Schema.TaggedError)\n\nWRONG: class MyError extends Error { ... }\nRIGHT: class MyError extends Schema.TaggedError<MyError>()(\"MyError\", { ... }) {}\n\nWRONG: Promise<T> as service method return type\nRIGHT: Effect.Effect<A, E> as service method return type\n\nWRONG: Calling Postgres.layer(...) in multiple places\nRIGHT: const dbLayer = Postgres.layer(...) — assign once, share reference\n\nWRONG: Scattered Effect.provide(...) throughout codebase\nRIGHT: Provide once at entry point via composed appLayer\n\nWRONG: Effect.provide inside service method implementations\nRIGHT: Layer composition handles all dependency wiring\n\nWRONG: Config.string(\"PORT\") for validated/branded values\nRIGHT: Schema.Config(\"PORT\", Port)\n\nWRONG: console.log(apiKey) or Config.string(\"SECRET\")\nRIGHT: Config.redacted(\"SECRET\") — logs as <redacted>\n\nWRONG: Raw string for domain IDs (userId: string)\nRIGHT: Schema.String.pipe(Schema.brand(\"UserId\"))\n\nWRONG: Plain generator function* for effectful code\nRIGHT: Effect.fn(\"name\")(function* (...) { ... }) for tracing + spans\n\nWRONG: Effect.gen without yield* (using .then or await)\nRIGHT: yield* inside Effect.gen(function* () { ... })\n\nWRONG: interface + manual tag for services\nRIGHT: class Db extends Context.Tag(\"@app/Db\")<Db, { ... }>() {}\n\nWRONG: Inline object literals for data models\nRIGHT: Schema.Class / Schema.TaggedClass for runtime-validated models\n\nWRONG: Union types via string literals or manual discriminants\nRIGHT: Schema.Union(VariantA, VariantB) + Match.valueTags\n\nWRONG: Mutable service interface properties\nRIGHT: readonly on all service interface properties\n\nWRONG: it(\"test\", async () => { ... }) with manual runPromise\nRIGHT: it.effect(\"test\", () => Effect.gen(function* () { ... }))\n\nWRONG: Writing full implementation before defining service contracts\nRIGHT: Sketch Context.Tag contracts first, implement layers after\n\n\n# Effect-First TypeScript — HTTP Server (HttpApi)\n\nPackage: @effect/platform (HttpApi, HttpApiBuilder, HttpApiEndpoint, HttpApiGroup, HttpApiMiddleware, HttpApiSecurity)\n\n## Imports\n\n    import {\n      HttpApi, HttpApiBuilder, HttpApiEndpoint, HttpApiGroup,\n      HttpApiMiddleware, HttpApiSecurity\n    } from \"@effect/platform\"\n\n## Step 1 — Define endpoints\n\n    import { HttpApiEndpoint, HttpApiGroup, HttpApi } from \"@effect/platform\"\n    import { Schema } from \"effect\"\n\n    class User extends Schema.Class<User>(\"User\")({\n      id: Schema.String,\n      name: Schema.String,\n    }) {}\n\n    class UserNotFound extends Schema.TaggedError<UserNotFound>()(\"UserNotFound\", {\n      id: Schema.String,\n    }) {}\n\n    class UsersGroup extends HttpApiGroup.make(\"users\")\n      .add(\n        HttpApiEndpoint.get(\"findById\", \"/users/:id\")\n          .setPath(Schema.Struct({ id: Schema.String }))\n          .addSuccess(User)\n          .addError(UserNotFound, { status: 404 })\n      )\n      .add(\n        HttpApiEndpoint.post(\"create\", \"/users\")\n          .setPayload(Schema.Struct({ name: Schema.NonEmptyString }))\n          .addSuccess(User, { status: 201 })\n      )\n      .prefix(\"/api\") {}\n\n    class MyApi extends HttpApi.make(\"myApi\").add(UsersGroup) {}\n\n\n## Step 2 — Implement handlers\n\n    import { HttpApiBuilder } from \"@effect/platform\"\n    import { Effect, Layer } from \"effect\"\n\n    const UsersGroupLive = HttpApiBuilder.group(MyApi, \"users\", (handlers) =>\n      handlers\n        .handle(\"findById\", ({ path }) =>\n          Effect.gen(function* () {\n            const users = yield* Users\n            return yield* users.findById(path.id)\n          })\n        )\n        .handle(\"create\", ({ payload }) =>\n          Effect.gen(function* () {\n            const users = yield* Users\n            return yield* users.create(payload.name)\n          })\n        )\n    )\n\n\n## Step 3 — Serve\n\n    import { NodeHttpServer } from \"@effect/platform-node\"\n    import { HttpApiBuilder } from \"@effect/platform\"\n    import { Layer, Effect } from \"effect\"\n    import { createServer } from \"node:http\"\n\n    const ApiLive = HttpApiBuilder.api(MyApi).pipe(\n      Layer.provide(UsersGroupLive),\n      Layer.provide(Users.layer)\n    )\n\n    const ServerLive = NodeHttpServer.layer(createServer, { port: 3000 })\n\n    const app = HttpApiBuilder.serve().pipe(\n      Layer.provide(ServerLive),\n      Layer.provide(ApiLive)\n    )\n\n    Layer.launch(app).pipe(Effect.runPromise)\n\n\n## HttpApi key constructors\n\n    HttpApi.make(id)                                — create API\n    HttpApiGroup.make(id)                           — create group\n    HttpApiEndpoint.get(name, path)                 — GET endpoint\n    HttpApiEndpoint.post(name, path)                — POST endpoint\n    HttpApiEndpoint.put(name, path)                 — PUT endpoint\n    HttpApiEndpoint.del(name, path)                 — DELETE endpoint\n    HttpApiEndpoint.patch(name, path)               — PATCH endpoint\n\n## Endpoint schema methods (chainable)\n\n    .setPath(Schema.Struct({ id: Schema.String }))  — path params\n    .setPayload(schema)                              — request body (POST/PUT/PATCH)\n    .setUrlParams(schema)                            — query string params (GET)\n    .setHeaders(schema)                              — required headers\n    .addSuccess(schema, { status: 200 })             — success response\n    .addError(schema, { status: 404 })               — error response\n    .prefix(\"/v1\")                                   — path prefix\n\n## Group / API composition\n\n    group.add(endpoint)                              — add endpoint to group\n    group.addError(schema, { status })               — shared error for all endpoints\n    group.prefix(\"/api\")                             — prefix all routes\n    api.add(group)                                   — add group to api\n    api.addError(schema, { status })                 — global error\n\n## Builder\n\n    HttpApiBuilder.api(MyApi)                        — Layer<HttpApi.Api>\n    HttpApiBuilder.group(api, name, build)           — Layer for a group\n    HttpApiBuilder.serve()                           — Layer that starts server\n    HttpApiBuilder.toWebHandler(layer)               — { handler, dispose } for Cloudflare/Bun\n\n\n## Security\n\n    import { HttpApiSecurity, HttpApiMiddleware } from \"@effect/platform\"\n\n    class AuthMiddleware extends HttpApiMiddleware.Tag<AuthMiddleware>()(\"AuthMiddleware\", {\n      provides: CurrentUser,\n      security: { bearer: HttpApiSecurity.bearer },\n    }) {}\n\n    // Apply to group\n    class SecureGroup extends HttpApiGroup.make(\"secure\")\n      .middleware(AuthMiddleware)\n      .add(...) {}\n\n    // Implement middleware\n    const AuthMiddlewareLive = Layer.effect(AuthMiddleware, Effect.gen(function* () {\n      return AuthMiddleware.of({\n        bearer: (token) => Effect.gen(function* () {\n          // validate token, return CurrentUser\n        })\n      })\n    }))\n\n\n## Anti-patterns\n\nWRONG: Manual HttpRouter.get/post for typed APIs\nRIGHT: HttpApi + HttpApiEndpoint for schema-validated, auto-documented endpoints\n\nWRONG: Parsing request body manually in handlers\nRIGHT: .setPayload(schema) — decoded and validated before handler runs\n\nWRONG: Returning HttpServerResponse from handlers\nRIGHT: Return domain types; framework encodes via success/error schemas\n\nWRONG: Implementing auth checks inside each handler\nRIGHT: HttpApiMiddleware + HttpApiSecurity applied to group or api\n\n\n# Effect-First TypeScript — HTTP Client\n\nPackage: @effect/platform (HttpClient, HttpClientRequest, HttpClientResponse, HttpClientError)\n\n## Imports\n\n    import { HttpClient, HttpClientRequest, HttpClientResponse, FetchHttpClient } from \"@effect/platform\"\n    import { NodeHttpClient } from \"@effect/platform-node\"\n    import { Effect, Schema } from \"effect\"\n\n## Basic GET\n\n    const fetchUser = Effect.fn(\"fetchUser\")(function* (id: string) {\n      const client = yield* HttpClient.HttpClient\n      const response = yield* client.get(`https://api.example.com/users/${id}`)\n      return yield* HttpClientResponse.schemaBodyJson(User)(response)\n    })\n\n    // Provide the client layer\n    fetchUser(\"u-1\").pipe(Effect.provide(FetchHttpClient.layer))\n\n## POST with JSON body\n\n    const createUser = Effect.fn(\"createUser\")(function* (name: string) {\n      const client = yield* HttpClient.HttpClient\n      const request = HttpClientRequest.post(\"https://api.example.com/users\").pipe(\n        HttpClientRequest.jsonBody({ name })\n      )\n      const response = yield* client.execute(request)\n      return yield* HttpClientResponse.schemaBodyJson(User)(response)\n    })\n\n## HttpApiClient — typed client from HttpApi definition\n\n    import { HttpApiClient } from \"@effect/platform\"\n\n    const program = Effect.gen(function* () {\n      const client = yield* HttpApiClient.make(MyApi, {\n        baseUrl: \"https://api.example.com\",\n      })\n      const user = yield* client.users.findById({ path: { id: \"u-1\" } })\n    })\n\n## Resilience — retry + timeout\n\n    const resilientFetch = fetchUser(\"u-1\").pipe(\n      Effect.retry(Schedule.exponential(\"200 millis\").pipe(Schedule.compose(Schedule.recurs(3)))),\n      Effect.timeout(\"10 seconds\"),\n      Effect.withSpan(\"fetchUser\")\n    )\n\n\n## Key types\n\n    HttpClient.HttpClient                — Context.Tag for the client service\n    HttpClientRequest.HttpClientRequest  — immutable request description\n    HttpClientResponse.HttpClientResponse — response with schema decoding\n    HttpClientError.HttpClientError      — typed error (RequestError | ResponseError)\n\n## Client methods\n\n    client.get(url, options?)            — GET request\n    client.post(url, options?)           — POST request\n    client.put(url, options?)            — PUT request\n    client.del(url, options?)            — DELETE request\n    client.patch(url, options?)          — PATCH request\n    client.head(url, options?)           — HEAD request\n    client.execute(request)              — execute arbitrary request\n\n## Response decoding\n\n    HttpClientResponse.schemaBodyJson(schema)(response)   — decode JSON body\n    HttpClientResponse.text(response)                     — body as string\n    HttpClientResponse.json(response)                     — body as unknown JSON\n    HttpClientResponse.stream(response)                   — body as Stream<Uint8Array>\n\n## Layers\n\n    FetchHttpClient.layer                — uses globalThis.fetch (browser, Cloudflare Workers, Bun)\n    NodeHttpClient.layer                 — uses Node.js undici\n\n## Anti-patterns\n\nWRONG: fetch(url).then(r => r.json())\nRIGHT: client.get(url) |> HttpClientResponse.schemaBodyJson(Schema)\n\nWRONG: Manual error handling for HTTP status codes\nRIGHT: HttpClient errors are typed; use Effect.catchTag(\"ResponseError\", ...)\n\nWRONG: Hardcoding fetch in service implementations\nRIGHT: Depend on HttpClient.HttpClient tag; provide FetchHttpClient.layer or NodeHttpClient.layer\n\nWRONG: Building typed API clients by hand\nRIGHT: HttpApiClient.make(MyApi) generates fully typed client from HttpApi definition\n\n\n# Effect-First TypeScript — SQL (@effect/sql)\n\n@effect/sql provides a tagged template literal SQL client, schema-validated queries, batched resolvers, and a Model system for domain objects with insert/update/json variants.\n\nPackage: @effect/sql (SqlClient, SqlSchema, SqlResolver, Model, Migrator)\nDB adapters: @effect/sql-pg, @effect/sql-sqlite-node, @effect/sql-mysql2, @effect/sql-mssql\n\n\n## Imports\n\n    import { SqlClient, SqlSchema, SqlResolver, Model } from \"@effect/sql\"\n    import { PgClient } from \"@effect/sql-pg\"        // or SqliteClient, etc.\n    import { Effect, Schema } from \"effect\"\n\n\n## SqlClient — tagged template queries\n\n    const program = Effect.gen(function* () {\n      const sql = yield* SqlClient.SqlClient\n\n      // select — returns ReadonlyArray<unknown>\n      const rows = yield* sql`SELECT * FROM users WHERE id = ${userId}`\n\n      // insert\n      yield* sql`INSERT INTO users ${sql.insert({ id, name, email })}`\n\n      // update\n      yield* sql`UPDATE users SET ${sql.update({ name, email })} WHERE id = ${id}`\n\n      // transactions\n      yield* sql.withTransaction(\n        Effect.gen(function* () {\n          yield* sql`INSERT INTO orders ${sql.insert(order)}`\n          yield* sql`UPDATE inventory SET qty = qty - 1 WHERE id = ${itemId}`\n        })\n      )\n    })\n\n\n## SqlSchema — validated queries\n\n    import { SqlClient, SqlSchema } from \"@effect/sql\"\n    import { Effect, Schema } from \"effect\"\n\n    const findUserById = SqlSchema.findOne({\n      Request: Schema.String,\n      Result: User,\n      execute: (id) => Effect.gen(function* () {\n        const sql = yield* SqlClient.SqlClient\n        return yield* sql`SELECT * FROM users WHERE id = ${id}`\n      }),\n    })\n\n    // SqlSchema variants:\n    // SqlSchema.findAll    — returns ReadonlyArray<A>\n    // SqlSchema.findOne    — returns Option<A>\n    // SqlSchema.single     — returns A (throws NoSuchElementException if missing)\n    // SqlSchema.void       — discards result\n\n\n## Model — domain objects with variants\n\n    import { Model } from \"@effect/sql\"\n    import { Schema } from \"effect\"\n\n    const GroupId = Schema.Number.pipe(Schema.brand(\"GroupId\"))\n\n    class Group extends Model.Class<Group>(\"Group\")({\n      id: Model.Generated(GroupId),\n      name: Schema.NonEmptyTrimmedString,\n      createdAt: Model.DateTimeInsertFromDate,\n      updatedAt: Model.DateTimeUpdateFromDate,\n    }) {}\n\n    // Variants auto-generated:\n    // Group            — select schema (all fields)\n    // Group.insert     — insert schema (id omitted, createdAt auto)\n    // Group.update     — update schema (all optional, updatedAt auto)\n    // Group.json       — JSON API schema\n    // Group.jsonCreate — JSON create schema\n    // Group.jsonUpdate — JSON update schema\n\n    // Model field helpers:\n    // Model.Generated(schema)              — omit from insert\n    // Model.GeneratedByApp(schema)         — required in insert, not from DB\n    // Model.DateTimeInsertFromDate         — auto DateTime on insert\n    // Model.DateTimeUpdateFromDate         — auto DateTime on update\n    // Model.Sensitive(schema)              — omit from json variants\n    // Model.FieldOption(schema)            — Option<A> field\n    // Model.JsonFromString(schema)         — JSON stored as string column\n\n\n## SqlResolver — batched queries with Effect Request\n\n    const UserById = SqlResolver.findById(\"UserById\", {\n      Id: UserId,\n      Result: User,\n      ResultId: (user) => user.id,\n      execute: (ids) => Effect.gen(function* () {\n        const sql = yield* SqlClient.SqlClient\n        return yield* sql`SELECT * FROM users WHERE id IN ${sql.in(ids)}`\n      }),\n    })\n\n    // Use:\n    const user = yield* UserById.execute(userId)\n\n    // SqlResolver variants:\n    // SqlResolver.findById   — returns Option<A>, keyed by ID\n    // SqlResolver.ordered    — results match request order 1:1\n    // SqlResolver.grouped    — group results by key (1:many)\n    // SqlResolver.void       — batched writes, no result\n\n\n## Model.makeRepository — CRUD from Model\n\n    const GroupRepo = Model.makeRepository(Group, {\n      tableName: \"groups\",\n      spanPrefix: \"GroupRepo\",\n      idColumn: \"id\",\n    })\n\n    // Provides: findById, insert, update, delete, etc.\n\n\n## Layers (provide at entry point)\n\n    // PostgreSQL\n    import { PgClient } from \"@effect/sql-pg\"\n    const DbLive = PgClient.layer({ url: \"postgres://localhost/mydb\" })\n\n    // SQLite\n    import { SqliteClient } from \"@effect/sql-sqlite-node\"\n    const DbLive = SqliteClient.layer({ filename: \"./data.db\" })\n\n    // Always assign to a const — memoization by reference\n    Effect.runPromise(program.pipe(Effect.provide(DbLive)))\n\n\n## Anti-patterns\n\nWRONG: String concatenation for SQL queries\nRIGHT: Tagged template: sql`SELECT * FROM users WHERE id = ${id}` (auto-parameterized)\n\nWRONG: Manual row-to-object mapping\nRIGHT: SqlSchema.findAll/findOne with Schema for validated decoding\n\nWRONG: N+1 queries in loops\nRIGHT: SqlResolver.findById / SqlResolver.grouped for automatic batching\n\nWRONG: Separate type definitions for insert vs select\nRIGHT: Model.Class generates all variants (select, insert, update, json) from one definition\n\nWRONG: Manual transaction begin/commit/rollback\nRIGHT: sql.withTransaction(effect) handles commit/rollback automatically\n\n\n# Effect-First TypeScript — CLI & Commands\n\nEffect provides two distinct capabilities:\n1. Command execution — run external processes via @effect/platform Command\n2. CLI argument parsing — use effect Config + Schema.Config for argv/env, or @effect/cli for full CLI apps\n\n\n## Imports\n\n    import { Command, CommandExecutor } from \"@effect/platform\"\n    import { NodeCommandExecutor, NodeFileSystem } from \"@effect/platform-node\"\n    import { Effect, Stream } from \"effect\"\n\n\n## Running external commands\n\n    const listFiles = Effect.gen(function* () {\n      // Simple: get stdout as string\n      const output = yield* Command.make(\"ls\", \"-la\").pipe(Command.string)\n\n      // With options\n      const result = yield* Command.make(\"git\", \"status\")\n        .pipe(\n          Command.workingDirectory(\"/path/to/repo\"),\n          Command.env({ GIT_AUTHOR_NAME: \"bot\" }),\n          Command.string\n        )\n\n      // Exit code only\n      const code = yield* Command.make(\"npm\", \"test\").pipe(Command.exitCode)\n\n      return output\n    })\n\n    // Provide the executor\n    listFiles.pipe(\n      Effect.provide(NodeCommandExecutor.layer),\n      Effect.provide(NodeFileSystem.layer)\n    )\n\n\n## Streaming output\n\n    // Stream stdout line by line\n    const logStream = Command.make(\"tail\", \"-f\", \"/var/log/app.log\").pipe(\n      Command.streamLines\n    )\n\n    // Process as a stream\n    const program = logStream.pipe(\n      Stream.filter((line) => line.includes(\"ERROR\")),\n      Stream.tap((line) => Effect.logError(line)),\n      Stream.runDrain\n    )\n\n    // Raw byte stream\n    const bytes = Command.make(\"cat\", \"file.bin\").pipe(Command.stream)\n\n\n## Piping commands\n\n    const pipeline = Command.make(\"cat\", \"data.csv\").pipe(\n      Command.pipeTo(Command.make(\"grep\", \"error\")),\n      Command.pipeTo(Command.make(\"wc\", \"-l\")),\n      Command.string\n    )\n\n\n## Process with stdin\n\n    const withInput = Command.make(\"wc\", \"-w\").pipe(\n      Command.feed(\"hello world this is a test\"),\n      Command.string\n    )\n\n\n## Command API reference\n\n    Command.make(cmd, ...args)           — create command\n    Command.string(cmd)                  — run, return stdout as string\n    Command.lines(cmd)                   — run, return stdout as string[]\n    Command.exitCode(cmd)                — run, return exit code\n    Command.stream(cmd)                  — stdout as Stream<Uint8Array>\n    Command.streamLines(cmd)             — stdout as Stream<string>\n    Command.start(cmd)                   — start Process (stdin/stdout/stderr access)\n    Command.pipeTo(target)               — pipe stdout to another command\n    Command.feed(input)                  — feed string to stdin\n    Command.workingDirectory(path)       — set cwd\n    Command.env(record)                  — set env vars\n    Command.runInShell(shell)            — run via shell (boolean | string)\n\n## Layers\n\n    NodeCommandExecutor.layer            — Node.js process execution\n    NodeFileSystem.layer                 — required by NodeCommandExecutor\n\n\n## CLI argument parsing with Config\n\nFor simple CLIs, use effect’s Config module (reads from env + argv):\n\n    import { Config, Effect, Schema } from \"effect\"\n\n    const program = Effect.gen(function* () {\n      const port = yield* Schema.Config(\"PORT\", Schema.NumberFromString.pipe(\n        Schema.int(), Schema.between(1, 65535)\n      ))\n      const verbose = yield* Config.withDefault(Config.boolean(\"VERBOSE\"), false)\n      const dbUrl = yield* Config.redacted(\"DATABASE_URL\")\n      yield* Effect.logInfo(`Starting on port ${port}`)\n    })\n\n\n## Anti-patterns\n\nWRONG: child_process.exec(cmd, callback)\nRIGHT: Command.make(cmd).pipe(Command.string)\n\nWRONG: Manually parsing stdout string into lines\nRIGHT: Command.streamLines(cmd) returns Stream<string>\n\nWRONG: process.env.PORT with manual parseInt\nRIGHT: Schema.Config(\"PORT\", Schema.NumberFromString) with validation\n\nWRONG: Forgetting to provide CommandExecutor layer\nRIGHT: Effect.provide(NodeCommandExecutor.layer) + Effect.provide(NodeFileSystem.layer)\n\n\n# Effect-First TypeScript — Streams\n\nStream<A, E, R> is a pull-based, backpressured sequence of values.\n\nPackage: effect (Stream, Sink, Channel)\n\n## Imports\n\n    import { Stream, Sink, Chunk, Effect, Schedule } from \"effect\"\n\n## Creating streams\n\n    // From values\n    Stream.make(1, 2, 3)\n    Stream.fromIterable([1, 2, 3])\n    Stream.range(1, 100)\n    Stream.empty\n\n    // From Effect (single value stream)\n    Stream.fromEffect(fetchUser(id))\n\n    // Repeated effect\n    Stream.repeatEffect(readSensor)\n    Stream.repeatEffectWithSchedule(pollApi, Schedule.spaced(\"5 seconds\"))\n\n    // Pagination\n    Stream.paginate(initialCursor, (cursor) => {\n      const page = fetchPage(cursor)\n      return [page.items, Option.fromNullable(page.nextCursor)]\n    })\n\n    // From async\n    Stream.fromAsyncIterable(asyncIter, (e) => new MyError({ cause: e }))\n    Stream.async((emit) => { /* push values via emit */ })\n\n    // Infinite\n    Stream.iterate(0, (n) => n + 1)\n    Stream.repeatValue(\"tick\")\n\n\n## Transforming streams\n\n    stream.pipe(\n      Stream.map((x) => x * 2),\n      Stream.filter((x) => x > 10),\n      Stream.take(5),\n      Stream.drop(2),\n      Stream.flatMap((x) => Stream.make(x, x + 1)),\n      Stream.mapEffect((x) => processItem(x)),\n      Stream.tap((x) => Effect.logInfo(`Processing: ${x}`)),\n      Stream.scan(0, (acc, x) => acc + x),\n    )\n\n    // Chunked operations (batch-efficient)\n    stream.pipe(\n      Stream.mapChunks((chunk) => Chunk.map(chunk, transform)),\n      Stream.grouped(100),           // group into chunks of 100\n      Stream.debounce(\"500 millis\"), // debounce emissions\n    )\n\n\n## Consuming streams\n\n    // Collect all (careful with large streams)\n    const items = yield* Stream.runCollect(stream)  // Chunk<A>\n\n    // Fold\n    const sum = yield* Stream.runFold(stream, 0, (acc, x) => acc + x)\n\n    // ForEach (side effects)\n    yield* Stream.runForEach(stream, (item) => processItem(item))\n\n    // Drain (discard values, run for effects)\n    yield* Stream.runDrain(stream)\n\n    // Count\n    const n = yield* Stream.runCount(stream)\n\n    // With Sink\n    yield* Stream.run(stream, Sink.collectAll())\n    yield* Stream.run(stream, Sink.foldLeft(0, (acc, x) => acc + x))\n\n\n## Combining streams\n\n    // Merge (interleave, concurrent)\n    Stream.merge(streamA, streamB)\n    Stream.mergeAll([streamA, streamB, streamC], { concurrency: 3 })\n\n    // Concat (sequential)\n    Stream.concat(streamA, streamB)\n\n    // Zip (pair elements)\n    Stream.zip(streamA, streamB)          // Stream<[A, B]>\n    Stream.zipWith(streamA, streamB, (a, b) => a + b)\n\n\n## Error handling\n\n    stream.pipe(\n      Stream.catchAll((e) => Stream.make(fallbackValue)),\n      Stream.catchTag(\"NetworkError\", (e) => Stream.empty),\n      Stream.retry(Schedule.exponential(\"1 second\")),\n    )\n\n\n## Sinks (stream consumers)\n\n    Sink.collectAll()                    — collect into Chunk<A>\n    Sink.foldLeft(init, f)               — fold without early termination\n    Sink.fold(init, contFn, f)           — fold with early termination\n    Sink.forEach(f)                      — side-effect per element\n    Sink.head                            — first element as Option<A>\n    Sink.last                            — last element as Option<A>\n    Sink.count                           — count elements\n    Sink.sum                             — sum numbers\n    Sink.take(n)                         — take first n into Chunk<A>\n\n\n## Common patterns\n\n    // Polling with schedule\n    const poller = Stream.repeatEffectWithSchedule(\n      checkStatus,\n      Schedule.spaced(\"10 seconds\")\n    ).pipe(\n      Stream.takeUntil((status) => status === \"complete\")\n    )\n\n    // Batched processing\n    const batchProcessor = eventStream.pipe(\n      Stream.grouped(50),\n      Stream.mapEffect((batch) => processBatch(Chunk.toReadonlyArray(batch)),\n        { concurrency: 3 }\n      ),\n      Stream.runDrain\n    )\n\n\n## Anti-patterns\n\nWRONG: Collecting unbounded stream into array\nRIGHT: Stream.runForEach or Stream.runFold for bounded consumption\n\nWRONG: for await (const x of asyncIter) with manual error handling\nRIGHT: Stream.fromAsyncIterable + Stream.mapEffect for typed errors\n\nWRONG: setInterval + mutable array for polling\nRIGHT: Stream.repeatEffectWithSchedule + Stream.takeUntil\n\nWRONG: Manual batching with counters\nRIGHT: Stream.grouped(n) + Stream.mapEffect with concurrency\n\nWRONG: Promise.all for concurrent stream processing\nRIGHT: Stream.mergeAll with concurrency option\n\n\n# Effect-First TypeScript — Concurrency\n\n## Imports\n\n    import { Effect, Fiber, FiberSet, FiberMap } from \"effect\"\n\n## Structured concurrency\n\n    // Run in parallel (all succeed or first error)\n    const result = yield* Effect.all([taskA, taskB, taskC], { concurrency: 2 })\n\n    // ForEach with concurrency + batching\n    yield* Effect.forEach(items, (item) => process(item), { concurrency: 5 })\n\n## Fork / join\n\n    const fiber = yield* Effect.fork(task)\n    const value = yield* Fiber.join(fiber)\n\n    // Fork and interrupt\n    const fiber = yield* Effect.fork(longRunning)\n    yield* Fiber.interrupt(fiber)\n\n    // Scoped fork (auto-interrupt on scope close)\n    const fiber = yield* Effect.forkScoped(task)\n    yield* Fiber.join(fiber)\n\n## Race\n\n    const fastest = yield* Effect.race(taskA, taskB)\n    const winner = yield* Effect.raceAll([taskA, taskB, taskC])\n\n## Fiber collections\n\n    const set = yield* FiberSet.make()\n    yield* FiberSet.run(set, taskA)\n    yield* FiberSet.run(set, taskB)\n    yield* FiberSet.join(set)\n\n    const map = yield* FiberMap.make()\n    yield* FiberMap.run(map, \"job-1\", taskA)\n    yield* FiberMap.run(map, \"job-2\", taskB)\n    yield* FiberMap.join(map, \"job-1\")\n\n## Interrupt\n\n    const fiber = yield* Effect.fork(task)\n    yield* Fiber.interrupt(fiber)\n    yield* Fiber.await(fiber)  // observe exit\n\n\n# Effect-First TypeScript — Resources & Scope\n\n## Imports\n\n    import { Effect, Layer, Scope, Pool, ScopedRef } from \"effect\"\n\n## acquireRelease\n\n    const file = yield* Effect.acquireRelease(\n      openFile(path),\n      (handle) => closeFile(handle)\n    )\n\n    const program = Effect.acquireUseRelease(\n      connectDb,\n      (db) => db.query(\"select * from users\"),\n      (db) => db.close\n    )\n\n## addFinalizer\n\n    const program = Effect.gen(function* () {\n      yield* Effect.addFinalizer(() => Effect.logInfo(\"cleanup\"))\n      return yield* doWork\n    })\n\n## Scope service\n\n    const scoped = Effect.scoped(\n      Effect.gen(function* () {\n        const scope = yield* Scope.Scope\n        return scope\n      })\n    )\n\n## Layer.scoped\n\n    class Connection extends Context.Tag(\"@app/Connection\")<\n      Connection,\n      { readonly query: (sql: string) => Effect.Effect<unknown[]> }\n    >() {}\n\n    const ConnectionLive = Layer.scoped(\n      Connection,\n      Effect.acquireRelease(connectDb, (db) => db.close)\n    )\n\n## Pools\n\n    const pool = yield* Pool.make({\n      acquire: connectDb,\n      size: 10,\n      timeToLive: \"10 minutes\",\n      concurrency: 2,\n    })\n\n    const db = yield* Pool.get(pool)\n\n## ScopedRef\n\n    const ref = yield* ScopedRef.fromAcquire(connectDb)\n    const db = yield* ScopedRef.get(ref)\n"
  }
} as const
